                                    <p className="text-2xl font-extrabold text-[#293c51] dark:text-gray-100">${(total * 0.5).toFixed(2)}</p>
                                    <p className="text-[9px] text-gray-400 mt-1 italic">Calculated based on 15 days remaining in cycle.</p>
                                </div>
