                        { id: 'd7', domainName: 'hdsgfjhjf.com', organizationName: 'anameischanged.info', creationDate: 'Oct 17, 2022', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true },
                        { id: 'd8', domainName: 'emad.eldeen', organizationName: 'anameischanged.info', creationDate: 'Dec 11, 2022', subDomainCount: 0, isDomainVerified: true, isMxVerified: false, isSpfVerified: false },
                    ]
                },
                { id: '2', name: 'tttt', domains: [] },
                { id: '3', name: 'tooli.test', domains: [] },
                { id: '4', name: 'mytest.com', domains: [] },
                { id: '5', name: 'test505.com', domains: [] },
                { id: '6', name: 'dsfgdfgfd', domains: [] },
                { id: '7', name: 'mohab.co', domains: [] },
