                                    <tbody><SPFRecordRow host="@" value="v=spf1 include:spf.worldposta.com ~all" /></tbody>
                                </table>
                            </div>
                        </Card>
                        <div className="flex justify-center gap-3">
                            <Button variant="ghost" onClick={handleSkipMx}>Skip for now</Button>
                            <Button onClick={handleVerifyMx} isLoading={mxVerificationStatus === 'verifying'} disabled={mxVerificationStatus === 'success'}>
                                {mxVerificationStatus === 'success' ? 'Records Verified!' : 'Verify Records'}
