                                    <th className="px-6 py-4 text-left font-medium">Subdomain</th>
                                    <th className="px-6 py-4 text-center font-medium">Verified</th>
                                    <th className="px-6 py-4 text-left font-medium">DNS Record</th>
                                    <th className="px-6 py-4 text-right"></th>
