                                                    <button className="inline-flex items-center text-[#679a41] hover:underline font-bold text-xs">
                                                        <Icon name="fas fa-check" className="mr-1.5" /> Verify
                                                    </button>
                                                )}
                                            </td>
                                            <td className="px-6 py-5">
                                                <div className="flex flex-col gap-1.5">
                                                    <div className="flex items-center gap-2">
                                                        <Icon name="fas fa-check-circle" className={`text-sm ${domain.isMxVerified ? 'text-[#679a41]' : 'text-gray-300'}`} />
                                                        <span className={`text-xs font-medium ${domain.isMxVerified ? 'text-[#679a41]' : 'text-gray-400'}`}>MX Verified</span>
                                                    </div>
                                                    <div className="flex items-center gap-2">
                                                        <Icon name="fas fa-check-circle" className={`text-sm ${domain.isSpfVerified ? 'text-[#679a41]' : 'text-gray-300'}`} />
                                                        <span className={`text-xs font-medium ${domain.isSpfVerified ? 'text-[#679a41]' : 'text-gray-400'}`}>SPF Verified</span>
                                                    </div>
                                                    {!domain.isMxVerified && (
                                                        <button className="text-left text-xs font-bold text-[#679a41] hover:underline mt-1">
