    };

    const handleDomainBlur = () => {
        if (!orgNameManuallyEdited.current) {
            setFormState(prev => ({ ...prev, organizationName: prev.domainToConfigure.trim() }));
        }
    };

    const handleOrgNameChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setFormState(prev => ({ ...prev, organizationName: e.target.value }));
        if (!orgNameManuallyEdited.current) orgNameManuallyEdited.current = true;
    };

    const resetStepper = () => {
        setCurrentStep(0);
        setFormState({ domainToConfigure: '', organizationName: '' });
        orgNameManuallyEdited.current = false;
        setDomainVerificationStatus('idle');
        setMxVerificationStatus('idle');
        setIsOrgNameEditable(false);
    }

    const handleStartAddProcess = () => {
        resetStepper();
        setView('stepper');
    };

    const handleVerifyDomain = () => {
        if (!formState.domainToConfigure.trim() || !formState.organizationName.trim()) {
            alert('Please enter a domain and organization name.');
            return;
        }
        setDomainVerificationStatus('verifying');
        setTimeout(() => {
            setDomainVerificationStatus('success');
            setTimeout(() => setCurrentStep(1), 1000);
        }, 1500);
    };

    const handleVerifyMx = () => {
        setMxVerificationStatus('verifying');
        setTimeout(() => {
            setMxVerificationStatus('success');
            setTimeout(() => addOrUpdateDomain(true), 1000);
        }, 1500);
    };

    const handleSkipMx = () => addOrUpdateDomain(false);

    const addOrUpdateDomain = (mxVerified: boolean) => {
        const newDomain: DomainInfo = {
            id: uuidv4(),
            domainName: formState.domainToConfigure,
            organizationName: formState.organizationName || formState.domainToConfigure,
            creationDate: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
            subDomainCount: 0,
            isDomainVerified: true,
            isMxVerified: mxVerified,
            isSpfVerified: mxVerified,
        };

        if (isNewDemoUser) {
            localStorage.setItem(DOMAIN_STORAGE_KEY, JSON.stringify([newDomain]));
            setOrganizations([{ id: 'demo-org', name: newDomain.organizationName, domains: [newDomain] }]);
            setActiveOrgId('demo-org');
            window.dispatchEvent(new CustomEvent('domainStateChange'));
        } else {
            // Find current active org or create new if none exists
            if (activeOrgId) {
                setOrganizations(prev => prev.map(o => o.id === activeOrgId ? { ...o, domains: [...o.domains, newDomain] } : o));
            } else {
                const newOrgId = uuidv4();
                setOrganizations(prev => [...prev, { id: newOrgId, name: newDomain.organizationName, domains: [newDomain] }]);
                setActiveOrgId(newOrgId);
            }
        }
        setView('table');
    }

    const StepperView = () => (
        <div className="p-6">
            <div className="w-full md:w-3/4 mx-auto mb-10">
                <Stepper steps={steps} currentStep={currentStep} />
            </div>
            <div className="mt-8 max-w-4xl mx-auto">
                {currentStep === 0 ? (
                    <div className="space-y-6 text-center">
                        <h3 className="text-xl font-bold text-[#293c51] dark:text-gray-100">Verify Domain Ownership</h3>
                        <div className="max-w-md mx-auto bg-gray-50 dark:bg-slate-800/50 p-6 rounded-xl space-y-4 text-left border border-gray-200 dark:border-slate-700">
                            <FormField id="domainToConfigure" label="Domain Name" value={formState.domainToConfigure} onChange={handleDomainChange} onBlur={handleDomainBlur} placeholder="yourdomain.com" required />
                            <FormField id="organizationName" label="Organization Name" value={formState.organizationName} onChange={handleOrgNameChange} required />
                        </div>
                        <Card className="text-left bg-gray-50/50 shadow-sm border border-gray-100 dark:border-slate-700">
                             <p className="text-sm mb-4 text-[#293c51] dark:text-gray-300 font-medium">Add this TXT record to your DNS settings:</p>
                             <div className="overflow-x-auto">
                                <table className="min-w-full">
                                    <thead className="bg-gray-100/50 dark:bg-slate-700/50">
                                        <tr className="text-xs text-gray-500 uppercase font-bold tracking-wider">
                                            <th className="px-4 py-2 text-left">Type</th>
                                            <th className="px-4 py-2 text-left">Name</th>
                                            <th className="px-4 py-2 text-left">Value</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y dark:divide-slate-700">
                                        <DNSRecordRow type="TXT" name="@" value={`wp-verification-${uuidv4().substring(0,8)}`} />
                                    </tbody>
                                </table>
                             </div>
                        </Card>
                        <div className="flex justify-center gap-3">
                            <Button variant="ghost" onClick={() => setView('table')}>Cancel</Button>
                            <Button onClick={handleVerifyDomain} isLoading={domainVerificationStatus === 'verifying'} disabled={!formState.domainToConfigure.trim() || domainVerificationStatus === 'success'}>
                                {domainVerificationStatus === 'success' ? 'Verified!' : 'Verify Now'}
                            </Button>
                        </div>
                    </div>
                ) : (
                    <div className="space-y-6 text-center">
                        <h3 className="text-xl font-bold text-[#293c51] dark:text-gray-100">Configure MX & SPF Records</h3>
                        <Card className="text-left shadow-sm border border-gray-100 dark:border-slate-700">
                            <p className="text-sm font-semibold mb-4 text-[#293c51] dark:text-gray-300">MX Records:</p>
                            <div className="overflow-x-auto mb-6">
                                <table className="min-w-full text-xs">
                                    <thead className="bg-gray-50 dark:bg-slate-700">
                                        <tr className="text-gray-500 font-bold tracking-wider uppercase">
                                            <th className="px-4 py-2 text-left">Host</th>
                                            <th className="px-4 py-2 text-left">TTL</th>
                                            <th className="px-4 py-2 text-left">Type</th>
                                            <th className="px-4 py-2 text-center">Priority</th>
                                            <th className="px-4 py-2 text-left">Value</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y dark:divide-slate-700">
                                        <MXRecordDisplayRow value="mail.worldposta.com" />
                                    </tbody>
                                </table>
                            </div>
                            <p className="text-sm font-semibold mb-4 text-[#293c51] dark:text-gray-300">SPF Record:</p>
                            <div className="overflow-x-auto border rounded-lg dark:border-slate-700">
                                <table className="min-w-full text-xs">
                                    <thead className="bg-gray-50 dark:bg-slate-700">
                                        <tr className="text-gray-500 font-bold tracking-wider uppercase">
                                            <th className="px-4 py-2 text-left">Host</th>
                                            <th className="px-4 py-2 text-left">Value</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <SPFRecordRow host="@" value="v=spf1 include:spf.worldposta.com ~all" />
                                    </tbody>
                                </table>
                            </div>
                        </Card>
                        <div className="flex justify-center gap-3">
                            <Button variant="ghost" onClick={handleSkipMx}>Skip for now</Button>
                            <Button onClick={handleVerifyMx} isLoading={mxVerificationStatus === 'verifying'} disabled={mxVerificationStatus === 'success'}>
                                {mxVerificationStatus === 'success' ? 'Records Verified!' : 'Verify Records'}
                            </Button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );

    const TableView = () => (
        <div className="flex flex-col lg:flex-row gap-8 items-start h-full">
            {/* Left Sidebar: Organizations as tabs */}
            <div className="w-full lg:w-72 flex-shrink-0">
                <div className="flex items-center justify-end mb-4 pr-1">
                    <Tooltip text="Add Organization">
                        <Button size="icon" variant="ghost" className="!h-7 !w-7 bg-[#679a41] text-white hover:bg-[#588836] rounded-md shadow-sm" onClick={handleStartAddProcess}>
                            <Icon name="fas fa-plus" className="text-[11px]" />
                        </Button>
                    </Tooltip>
                </div>
                <div className="space-y-1.5 max-h-[calc(100vh-280px)] overflow-y-auto pr-2 custom-scrollbar">
                    {organizations.map(org => (
                        <button
                            key={org.id}
                            onClick={() => setActiveOrgId(org.id)}
                            className={`w-full text-left px-5 py-3.5 rounded-lg text-sm font-semibold transition-all duration-200
                                ${activeOrgId === org.id 
                                    ? 'bg-[#679a41] text-white shadow-md shadow-green-500/20 translate-x-1' 
                                    : 'bg-gray-100 text-gray-500 hover:bg-gray-200 dark:bg-slate-800 dark:text-gray-400 dark:hover:bg-slate-700'}`}
                        >
                            <div className="flex items-center justify-between">
                                <span className="truncate">{org.name}</span>
                                {activeOrgId === org.id && <Icon name="fas fa-chevron-right" className="text-[10px] ml-2 opacity-70" />}
                            </div>
                        </button>
                    ))}
                    {organizations.length === 0 && <p className="text-center text-xs text-gray-400 py-6 italic">No organizations found</p>}
                </div>
            </div>

            {/* Right Side: Domains */}
            <div className="flex-grow w-full">
                <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-8">
                    <h2 className="text-xl font-bold text-[#679a41] dark:text-emerald-400 flex items-center gap-2">
                        Domains
                    </h2>
                    <div className="flex items-center gap-3 w-full sm:w-auto">
                        <Button variant="primary" className="!bg-[#679a41] !border-none text-white text-xs px-5 py-2 font-bold shadow-sm" leftIconName="fas fa-plus" onClick={handleStartAddProcess}>
                            Add Domain
                        </Button>
                        <Button variant="primary" className="!bg-[#889a74] !border-none text-white text-xs px-5 py-2 font-bold shadow-sm">
                            View Organization
                        </Button>
                    </div>
                </div>

                <div className="overflow-x-auto bg-white dark:bg-slate-900/40 rounded-xl border border-gray-100 dark:border-slate-800 shadow-sm">
                    <table className="min-w-full">
                        <thead>
                            <tr className="bg-gray-50/50 dark:bg-slate-800/50 text-gray-500 text-xs font-bold uppercase tracking-wider">
                                <th className="px-6 py-4 text-left">Domain Name</th>
                                <th className="px-6 py-4 text-left">Creation Date</th>
                                <th className="px-6 py-4 text-left">Subdomain</th>
                                <th className="px-6 py-4 text-center">Verified</th>
                                <th className="px-6 py-4 text-left">Health check</th>
                                <th className="px-6 py-4 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-slate-800">
                            {activeOrg && activeOrg.domains.length > 0 ? (
                                activeOrg.domains.map(domain => (
                                    <tr key={domain.id} className="text-gray-700 dark:text-gray-300 text-sm hover:bg-gray-50/30 dark:hover:bg-slate-800/20 transition-colors group">
                                        <td className="px-6 py-5 font-medium">{domain.domainName}</td>
                                        <td className="px-6 py-5 text-gray-500">{domain.creationDate || '-'}</td>
                                        <td className="px-6 py-5 text-gray-500">{domain.subDomainCount || '-'}</td>
                                        <td className="px-6 py-5 text-center">
                                            {domain.isDomainVerified ? (
                                                <span className="inline-flex items-center px-4 py-1.5 bg-[#679a41] text-white text-[10px] font-extrabold rounded-sm uppercase tracking-widest shadow-sm">
                                                    VERIFIED
                                                </span>
                                            ) : (
                                                <button className="inline-flex items-center text-gray-500 hover:text-[#679a41] transition-colors font-bold text-[11px] uppercase tracking-wide">
                                                    <Icon name="fas fa-check" className="mr-1.5" /> Verify
                                                </button>
                                            )}
                                        </td>
                                        <td className="px-6 py-5">
                                            <div className="flex flex-col gap-1.5">
                                                <div className="flex items-center gap-2.5">
                                                    <Icon name="fas fa-check-circle" className={`text-[13px] ${domain.isMxVerified ? 'text-[#679a41]' : 'text-gray-300 dark:text-slate-700'}`} />
                                                    <span className={`text-[11px] font-bold tracking-tight uppercase ${domain.isMxVerified ? 'text-[#679a41]' : 'text-gray-400 dark:text-slate-600'}`}>MX Verified</span>
                                                </div>
                                                <div className="flex items-center gap-2.5">
                                                    <Icon name="fas fa-check-circle" className={`text-[13px] ${domain.isSpfVerified ? 'text-[#679a41]' : 'text-gray-300 dark:text-slate-700'}`} />
                                                    <span className={`text-[11px] font-bold tracking-tight uppercase ${domain.isSpfVerified ? 'text-[#679a41]' : 'text-gray-400 dark:text-slate-600'}`}>SPF Verified</span>
                                                </div>
                                                {!domain.isMxVerified && (
                                                    <button className="text-left text-[10px] font-black text-[#679a41] hover:underline mt-1 uppercase tracking-widest flex items-center">
                                                        <Icon name="fas fa-check" className="mr-1" /> Verify DNS Records
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-5 text-right">
                                            <button className="text-gray-300 hover:text-[#293c51] dark:hover:text-white p-2 transition-colors">
                                                <Icon name="fas fa-ellipsis-v" />
                                            </button>
                                        </td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan={6} className="text-center py-24">
                                        <div className="flex flex-col items-center justify-center opacity-40">
                                            <Icon name="fas fa-globe" className="text-4xl mb-3 text-gray-400" />
                                            <p className="text-sm font-medium italic text-gray-500">
                                                {activeOrg ? 'No domains found in this organization' : 'Select an organization to view active domains'}
                                            </p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );

    return (
        <Card title="" className="!p-8 min-h-[700px] shadow-lg border border-gray-100 dark:border-slate-800 animate-fade-in">
            <div className="mb-10 flex justify-between items-center border-b border-gray-100 dark:border-slate-800 pb-5">
                 <h1 className="text-2xl font-black text-[#293c51] dark:text-gray-100 tracking-tight">Organizations</h1>
            </div>
            {view === 'stepper' ? <StepperView /> : <TableView />}
        </Card>
    );
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Card, Stepper, FormField, Button, Icon, Tooltip, Pagination } from '@/components/ui';
import { v4 as uuidv4 } from 'uuid';
import { useAuth } from '@/context';
import { Link } from 'react-router-dom';

interface DomainInfo {
    id: string;
    domainName: string;
    organizationName: string;
    creationDate: string;
    subDomainCount: number;
    isDomainVerified: boolean;
    isMxVerified: boolean;
    isSpfVerified: boolean;
    healthStatus: 'healthy' | 'warning' | 'unhealthy';
}

interface Organization {
    id: string;
    name: string;
    domains: DomainInfo[];
}

const DNSRecordRow: React.FC<{type: string, name: string, value: string, priority?: number}> = ({type, name, value, priority}) => {
    const [copied, setCopied] = useState(false);
    const handleCopy = (text: string) => {
        navigator.clipboard.writeText(text).then(() => {
            setCopied(true);
            setTimeout(() => setCopied(false), 2000);
        }, (err) => {
            alert('Failed to copy text.');
        });
    };

    return (
        <tr className="border-b dark:border-gray-700 last:border-b-0 text-[#293c51] dark:text-gray-200">
            <td className="px-4 py-3 text-sm font-semibold">{type}</td>
            <td className="px-4 py-3 text-sm font-mono">{name}</td>
            <td className="px-4 py-3 text-sm">
                <div className="flex items-center justify-between">
                    <span className="font-mono break-all">{value}{priority && ` (Priority: ${priority})`}</span>
                    <Button size="icon" variant="ghost" onClick={() => handleCopy(priority ? `${value} (Priority: ${priority})` : value)} title="Copy value">
                        <Icon name={copied ? "fas fa-check" : "far fa-copy"} className={copied ? "text-green-500" : ""} />
                    </Button>
                </div>
            </td>
        </tr>
    );
};

