                            View Organization
                        </Button>
                    </div>
                </div>

                <div className="overflow-x-auto border rounded-lg dark:border-gray-700 bg-white dark:bg-slate-800">
                    <table className="min-w-full">
                        <thead className="bg-gray-50 dark:bg-slate-700">
                            <tr className="text-gray-500 text-xs font-bold uppercase tracking-wider">
                                <th className="px-6 py-4 text-left">Domain Name</th>
                                <th className="px-6 py-4 text-left">Creation Date</th>
                                <th className="px-6 py-4 text-left">Subdomain</th>
                                <th className="px-6 py-4 text-center">Verified</th>
                                <th className="px-6 py-4 text-left">Health check</th>
                                <th className="px-6 py-4 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                            {activeOrg && activeOrg.domains.length > 0 ? (
                                activeOrg.domains.map(domain => (
                                    <tr key={domain.id} className="text-gray-700 dark:text-gray-300 text-sm hover:bg-gray-50/30 dark:hover:bg-slate-800/20 transition-colors group">
