export const OrgsAndDomainsPage: React.FC = () => {
    const { user } = useAuth();
    const isNewDemoUser = user?.email === 'new.user@worldposta.com';
    const DOMAIN_STORAGE_KEY = 'demoUserDomains';

    const [organizations, setOrganizations] = useState<Organization[]>([]);
    const [activeOrgId, setActiveOrgId] = useState<string | null>(null);
    const [view, setView] = useState<'table' | 'stepper'>('table');
    const [currentStep, setCurrentStep] = useState(0);

    const steps = [
        { name: 'Verify Domain' },
        { name: 'Configure MX & SPF' }
    ];

    const [formState, setFormState] = useState({
        domainToConfigure: '',
        organizationName: '',
    });
    const orgNameManuallyEdited = useRef(false);
    const [domainVerificationStatus, setDomainVerificationStatus] = useState<'idle' | 'verifying' | 'success' | 'failed'>('idle');
    const [mxVerificationStatus, setMxVerificationStatus] = useState<'idle' | 'verifying' | 'success' | 'failed'>('idle');

    // Initial mock data
    useEffect(() => {
        if (!isNewDemoUser) {
            const mockOrgs: Organization[] = [
                {
                    id: '1', name: 'anameischanged.info', domains: [
                        { id: 'd1', domainName: 'anameischanged.info', organizationName: 'anameischanged.info', creationDate: '-', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                        { id: 'd2', domainName: 'Test.domain', organizationName: 'anameischanged.info', creationDate: 'Nov 18, 2019', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                        { id: 'd3', domainName: 'cpspharma.com', organizationName: 'anameischanged.info', creationDate: 'Jul 29, 2021', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                        { id: 'd4', domainName: 'wwwwwqqqq.saq', organizationName: 'anameischanged.info', creationDate: 'Sep 9, 2021', subDomainCount: 0, isDomainVerified: false, isMxVerified: true, isSpfVerified: true, healthStatus: 'warning' },
                        { id: 'd5', domainName: 'rowanda.net', organizationName: 'anameischanged.info', creationDate: 'Jun 29, 2022', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                        { id: 'd6', domainName: 'nour.net', organizationName: 'anameischanged.info', creationDate: 'Jun 29, 2022', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                        { id: 'd7', domainName: 'hdsgfjhjf.com', organizationName: 'anameischanged.info', creationDate: 'Oct 17, 2022', subDomainCount: 0, isDomainVerified: true, isMxVerified: true, isSpfVerified: true, healthStatus: 'healthy' },
                    ]
                },
                { id: '2', name: 'tttt', domains: [] },
                { id: '3', name: 'tooli.test', domains: [] },
                { id: '4', name: 'mytest.com', domains: [] },
                { id: '5', name: 'test505.com', domains: [] },
                { id: '6', name: 'dsfgdfgfd', domains: [] },
                { id: '7', name: 'mohab.co', domains: [] },
                { id: '8', name: 'anametestdomain', domains: [] },
                { id: '9', name: 'dsfffs.sa', domains: [] },
            ];
            setOrganizations(mockOrgs);
            setActiveOrgId('1');
        }
    }, [isNewDemoUser]);

    useEffect(() => {
        if (isNewDemoUser) {
            try {
                const storedDomains = localStorage.getItem(DOMAIN_STORAGE_KEY);
                const loadedDomains = storedDomains ? JSON.parse(storedDomains) : [];
                if (loadedDomains.length > 0) {
                    setOrganizations([{
                        id: 'demo-org',
                        name: loadedDomains[0].organizationName || loadedDomains[0].domainName,
                        domains: loadedDomains
                    }]);
                    setActiveOrgId('demo-org');
                    setView('table');
                } else {
                    setView('stepper');
                }
            } catch (e) {
                console.error("Failed to load domains from localStorage", e);
                setView('stepper');
            }
        }
    }, [isNewDemoUser]);

    const activeOrg = useMemo(() => {
        return organizations.find(o => o.id === activeOrgId) || null;
    }, [organizations, activeOrgId]);

    const resetStepper = () => {
        setCurrentStep(0);
        setFormState({ domainToConfigure: '', organizationName: '' });
        orgNameManuallyEdited.current = false;
        setDomainVerificationStatus('idle');
        setMxVerificationStatus('idle');
    }

    const handleStartAddProcess = () => {
        resetStepper();
        setView('stepper');
    };

    const handleVerifyDomain = () => {
        if (!formState.domainToConfigure.trim() || !formState.organizationName.trim()) {
            alert('Please enter a domain and organization name.');
            return;
        }
        setDomainVerificationStatus('verifying');
        setTimeout(() => {
            setDomainVerificationStatus('success');
            setTimeout(() => setCurrentStep(1), 1000);
        }, 1500);
    };

    const handleVerifyMx = () => {
        setMxVerificationStatus('verifying');
        setTimeout(() => {
            setMxVerificationStatus('success');
            setTimeout(() => addOrUpdateDomain(true), 1000);
        }, 1500);
    };

    const handleSkipMx = () => addOrUpdateDomain(false);

    const addOrUpdateDomain = (mxVerified: boolean) => {
        const newDomain: DomainInfo = {
            id: uuidv4(),
            domainName: formState.domainToConfigure,
            organizationName: formState.organizationName || formState.domainToConfigure,
            creationDate: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
            subDomainCount: 0,
            isDomainVerified: true,
            isMxVerified: mxVerified,
            isSpfVerified: mxVerified,
            healthStatus: mxVerified ? 'healthy' : 'warning',
        };

        if (isNewDemoUser) {
            localStorage.setItem(DOMAIN_STORAGE_KEY, JSON.stringify([newDomain]));
            setOrganizations([{ id: 'demo-org', name: newDomain.organizationName, domains: [newDomain] }]);
            setActiveOrgId('demo-org');
            window.dispatchEvent(new CustomEvent('domainStateChange'));
        } else {
            if (activeOrgId) {
                setOrganizations(prev => prev.map(o => o.id === activeOrgId ? { ...o, domains: [...o.domains, newDomain] } : o));
            } else {
