                                                    <span>HEALTH OK</span>
                                                </div>
                                            ) : domain.healthStatus === 'warning' ? (
                                                <div className="flex items-center gap-2 text-yellow-500 font-bold text-[11px] uppercase tracking-wider">
                                                    <Icon name="fas fa-exclamation-triangle" className="text-sm" />
                                                    <span>CHECK</span>
                                                </div>
                                            ) : (
                                                <div className="flex items-center gap-2 text-red-500 font-bold text-[11px] uppercase tracking-wider">
                                                    <Icon name="fas fa-exclamation-circle" className="text-sm" />
                                                    <span>UNHEALTHY</span>
