            <Button variant="primary" className="!bg-[#889a74] !border-none text-white text-xs px-5 py-2 font-bold shadow-sm">
                View Organization
            </Button>
        </div>
    );

    return (
        <Card title="Organizations" titleActions={titleActions} className="!p-8 min-h-[700px] shadow-lg border border-gray-100 dark:border-slate-800">
            {view === 'stepper' && <StepperView />}
            {view === 'table' && <TableView />}
            {view === 'dns' && <div className="max-w-5xl mx-auto"><DNSConfigView domain={selectedDomainForDns} onBack={handleBackToTable} /></div>}
        </Card>
    );
};

