        // Fix: Explicitly typed the return value of getRecStatus to ensure it returns the literal union instead of string.
        const getRecStatus = (index: number): VerificationStatus => {
            if (hStatus === 'healthy') return 'success';
            if (hStatus === 'unhealthy') return 'error';
