                const newOrgId = uuidv4();
                setOrganizations(prev => [...prev, { id: newOrgId, name: newDomain.organizationName, description: '', primaryDomain: newDomain.domainName, domains: [newDomain] }]);
                setActiveOrgId(newOrgId);
