            <td className="px-4 py-4 text-sm font-mono">{ttl}</td>
            <td className="px-4 py-4 text-sm font-semibold">MX</td>
            <td className="px-4 py-4 text-sm text-center">{priority}</td>
            <td className="px-4 py-4 text-sm">
