                        { id: 'd8', domainName: 'ed-holdings.co', organizationName: 'Alpha Solutions Group', creationDate: 'Dec 11, 2022', subDomainCount: 0, isMxVerified: false, isSpfVerified: false, healthStatus: 'unhealthy' },
