import React from 'react';
import { Icon } from './Icon';
import { Spinner } from './Spinner';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'outline' | 'ghost' | 'dark';
  size?: 'sm' | 'md' | 'lg' | 'icon';
  isLoading?: boolean;
  fullWidth?: boolean;
  leftIconName?: string;
  leftIconClassName?: string;
  // Fix: Added rightIconName and rightIconClassName to ButtonProps to resolve type errors in components using icons on the right
  rightIconName?: string;
  rightIconClassName?: string;
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  isLoading = false, 
  fullWidth = false, 
  className, 
  leftIconName, 
  leftIconClassName,
  // Fix: Destructured new right icon props
  rightIconName,
  rightIconClassName,
  ...props 
}, ref) => {
  const baseStyles = "font-semibold rounded-md focus:outline-none focus:ring-2 focus:ring-offset-1 dark:focus:ring-offset-gray-800 transition-colors duration-150 ease-in-out inline-flex items-center justify-center";
  const variantStyles = {
    primary: "bg-[#679a41] text-white hover:bg-[#588836] focus:ring-[#679a41] dark:bg-emerald-500 dark:hover:bg-emerald-600 dark:focus:ring-emerald-500",
    secondary: "bg-[#293c51] text-white hover:bg-[#1f2d3d] focus:ring-[#293c51] dark:bg-sky-600 dark:hover:bg-sky-700 dark:focus:ring-sky-600",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500 dark:bg-red-500 dark:hover:bg-red-600 dark:focus:ring-red-500",
    outline: "bg-transparent text-[#679a41] border border-[#679a41] hover:bg-[#679a41]/10 focus:ring-[#679a41] dark:text-emerald-400 dark:border-emerald-400 dark:hover:bg-emerald-400/10",
    ghost: "bg-transparent text-[#293c51] hover:bg-gray-100 focus:ring-[#679a41] dark:text-gray-300 dark:hover:bg-gray-700 dark:focus:ring-emerald-400",
    dark: "bg-[#1F2937] text-gray-300 hover:bg-[#374151] focus:ring-[#1F2937] border border-[#374151]"
  };
  const sizeStyles = {
    sm: "px-3 py-1.5 text-xs h-8",
    md: "px-4 py-2 text-sm h-10",
    lg: "px-6 py-3 text-base h-12",
    icon: "p-2",
  };
  const widthStyles = fullWidth ? "w-full" : "";

  return (
    <button
      ref={ref}
      className={`${baseStyles} ${variantStyles[variant]} ${sizeStyles[size]} ${widthStyles} ${isLoading || props.disabled ? 'opacity-75 cursor-not-allowed' : ''} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <div className="flex items-center justify-center">
          <Spinner size="sm" />
          <span className="ml-2">Loading...</span>
        </div>
      ) : (
        <>
        {leftIconName && <Icon name={leftIconName} className={`${children ? 'mr-2' : ''} ${leftIconClassName || ''}`} />}
        {children}
        {/* Fix: Render right icon if rightIconName is provided */}
        {rightIconName && <Icon name={rightIconName} className={`${children ? 'ml-2' : ''} ${rightIconClassName || ''}`} />}
        </>
      )}
    </button>
  );
});

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from '@google/genai';
import { Icon } from './Icon';
import { Button } from './Button';
import { Logo } from './Logo';

interface Message {
  id: string;
  text: string;
  sender: 'user' | 'ai';
}

// Fix: Removed global initialization of GoogleGenAI and Chat to comply with guidelines of creating a fresh instance before each API call.

export const Chatbot: React.FC = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [messages, setMessages] = useState<Message[]>([
        { id: 'initial-ai-message', text: "Hello! I'm the WorldPosta Assistant. How can I help you today?", sender: 'ai' }
    ]);
    const [inputValue, setInputValue] = useState('');
    const [isLoading, setIsLoading] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const inputRef = useRef<HTMLInputElement>(null);

    // Fix: Using a ref to maintain chat context across messages within the component session
    const chatRef = useRef<Chat | null>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    };

    useEffect(scrollToBottom, [messages]);

    useEffect(() => {
        if(isOpen) {
            inputRef.current?.focus();
        }
    }, [isOpen]);

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        const userMessage = inputValue.trim();
        // Fix: Use process.env.API_KEY directly as required
        if (!userMessage || isLoading || !process.env.API_KEY) return;

        const newUserMessage: Message = { id: Date.now().toString(), text: userMessage, sender: 'user' };
        setMessages(prev => [...prev, newUserMessage]);
        setInputValue('');
        setIsLoading(true);

        const aiMessageId = (Date.now() + 1).toString();
        // Add a placeholder for the AI response
        setMessages(prev => [...prev, { id: aiMessageId, text: '', sender: 'ai' }]);

        try {
            // Fix: Create a new GoogleGenAI instance right before making the API call
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

            // Fix: Initialize the chat session if it doesn't exist for this component instance
            if (!chatRef.current) {
                chatRef.current = ai.chats.create({
                    model: 'gemini-3-flash-preview',
                    config: {
                        systemInstruction: 'You are a friendly and helpful assistant for WorldPosta. Your goal is to assist users with their questions about products, billing, and support.',
                    },
                });
            }

            const responseStream = await chatRef.current.sendMessageStream({ message: userMessage });
            for await (const chunk of responseStream) {
                const chunkText = chunk.text || '';
                setMessages(prev => prev.map(msg => 
                    msg.id === aiMessageId ? { ...msg, text: msg.text + chunkText } : msg
                ));
            }
        } catch (error) {
            console.error('Error sending message to Gemini:', error);
            setMessages(prev => prev.map(msg => 
                msg.id === aiMessageId ? { ...msg, text: "Sorry, I'm having trouble connecting right now. Please try again later." } : msg
            ));
        } finally {
            setIsLoading(false);
        }
    };

    // Fix: Check for API Key availability to toggle locked state UI
    const isApiKeyMissing = !process.env.API_KEY;

    return (
        <>
            <div className={`fixed bottom-6 right-6 z-50 transition-all duration-300 ${isOpen ? 'scale-90 opacity-0 pointer-events-none' : 'scale-100 opacity-100'}`}>
                <Button
                    variant="primary"
                    onClick={() => setIsOpen(true)}
                    className="rounded-full !p-0 w-12 h-12 shadow-lg hover:scale-110 transform transition-transform hover:shadow-xl"
                    aria-label="Open chat"
                >
                    <Icon name="fas fa-comment-dots" className="text-lg" />
                </Button>
            </div>

            <div
                className={`fixed bottom-6 right-6 z-50 w-[calc(100%-3rem)] max-w-sm h-[70vh] max-h-[600px] bg-white dark:bg-slate-800 rounded-2xl shadow-2xl flex flex-col transition-all duration-300 ease-in-out origin-bottom-right ${isOpen ? 'scale-100 opacity-100' : 'scale-90 opacity-0 pointer-events-none'}`}
            >
                {/* Header */}
                <div className="flex-shrink-0 flex items-center justify-between p-4 border-b border-gray-200 dark:border-slate-700">
                    <div className="flex items-center gap-2">
                         <Logo iconClassName="h-7 w-auto" />
                         <h3 className="font-semibold text-lg text-[#293c51] dark:text-gray-100">Assistant</h3>
                    </div>
                    <Button variant="ghost" size="icon" onClick={() => setIsOpen(false)} aria-label="Close chat">
                        <Icon name="fas fa-times" />
                    </Button>
                </div>

                {/* Messages */}
                <div className="flex-grow p-4 overflow-y-auto space-y-4">
                    {messages.map((message) => (
                        <div key={message.id} className={`flex items-end gap-2 ${message.sender === 'user' ? 'justify-end' : 'justify-start'}`}>
                            {message.sender === 'ai' && (
                                <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-slate-700 flex items-center justify-center flex-shrink-0">
                                     <Icon name="fas fa-robot" className="text-gray-500 dark:text-gray-400" />
                                </div>
                            )}
                            <div
                                className={`max-w-[80%] rounded-2xl px-4 py-2 text-sm ${
                                    message.sender === 'user'
                                        ? 'bg-[#679a41] text-white rounded-br-none'
                                        : 'bg-gray-100 dark:bg-slate-700 text-[#293c51] dark:text-gray-200 rounded-bl-none'
                                }`}
                            >
                                <p className="whitespace-pre-wrap">{message.text}</p>
                            </div>
                        </div>
                    ))}
                    {isLoading && (
                         <div className="flex items-end gap-2 justify-start">
                             <div className="w-8 h-8 rounded-full bg-gray-200 dark:bg-slate-700 flex items-center justify-center flex-shrink-0">
                                <Icon name="fas fa-robot" className="text-gray-500 dark:text-gray-400" />
                            </div>
                             <div className="max-w-[80%] rounded-2xl px-4 py-3 bg-gray-100 dark:bg-slate-700 rounded-bl-none flex items-center space-x-1.5">
                                 <span className="w-2 h-2 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce delay-0"></span>
                                 <span className="w-2 h-2 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce delay-150"></span>
                                 <span className="w-2 h-2 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce delay-300"></span>
                             </div>
                         </div>
                    )}
                     <div ref={messagesEndRef} />
                </div>

                 {/* Input */}
                <div className="flex-shrink-0 p-4 border-t border-gray-200 dark:border-slate-700">
                    {isApiKeyMissing ? (
                         <div className="text-center text-xs text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-900/30 p-2 rounded-md">
                            <Icon name="fas fa-exclamation-triangle" className="mr-1" />
                            Chatbot functionality is currently unavailable due to a missing API key.
                        </div>
                    ) : (
                        <form onSubmit={handleSendMessage} className="flex items-center gap-2">
                            <input
                                ref={inputRef}
                                type="text"
                                value={inputValue}
                                onChange={(e) => setInputValue(e.target.value)}
                                placeholder="Type a message..."
                                disabled={isLoading}
                                className="flex-grow w-full px-4 py-2 border rounded-full focus:outline-none focus:ring-2 focus:ring-[#679a41] dark:focus:ring-emerald-400 focus:border-[#679a41] dark:focus:border-emerald-400 border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-700 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 text-sm"
                            />
                            <Button type="submit" disabled={isLoading || !inputValue.trim()} className="rounded-full !p-0 w-10 h-10 flex-shrink-0">
                                <Icon name="fas fa-paper-plane" />
                            </Button>
                        </form>
                    )}
                </div>
            </div>
        </>
    );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Card, FormField, Button, Icon, CollapsibleSection, LineChart, BarChart, MultiSegmentDoughnutChart, StatCard, Pagination, Modal, Spinner } from '@/components/ui';
import { mockSmtpLogs, mockMailboxDomains } from '@/data';
import type { SmtpLogEntry, SmtpLogAction, SmtpLogStatus, AIAnalysisResult } from '@/types';
import { GoogleGenAI, Type } from "@google/genai";
import { Link } from 'react-router-dom';
import { useAppLayout, useAuth } from '@/context';


// Fix: Removed global initialization to ensure a fresh GoogleGenAI instance is created right before usage as per coding guidelines.


const SMTP_ACTIONS: SmtpLogAction[] = ['PASS', 'DELIVER', 'ARCHIVE', 'QUARANTINE', 'REJECT'];
const SMTP_STATUSES: SmtpLogStatus[] = ['Passed', 'Archived', 'Rejected (Data)', 'Rejected (Block)', 'Spam (Confirmed)', 'Spam (Scam)', 'Rejected (Suspect)', 'User Invalid'];

interface Filters {
    from: string;
    to: string;
    subject: string;
    action: SmtpLogAction | 'ALL';
    dateFrom: string;
    dateTo: string;
    statuses: SmtpLogStatus[];
}

const initialFilters: Filters = {
    from: '',
    to: '',
    subject: '',
    action: 'ALL',
    dateFrom: '',
    dateTo: '',
    statuses: [],
};

interface FilterPanelProps {
    isOpen: boolean;
    onClose: () => void;
    onApply: (newFilters: Filters) => void;
    onClear: () => void;
    currentFilters: Filters;
}

const FilterPanel: React.FC<FilterPanelProps> = ({ isOpen, onClose, onApply, onClear, currentFilters }) => {
    const [localFilters, setLocalFilters] = useState<Filters>(currentFilters);

    useEffect(() => {
        if (isOpen) {
            setLocalFilters(currentFilters);
        }
    }, [isOpen, currentFilters]);

    const handleLocalChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setLocalFilters(prev => ({ ...prev, [name]: value }));
    };

    const handleStatusChange = (status: SmtpLogStatus, checked: boolean) => {
        setLocalFilters(prev => {
            const newStatuses = checked
                ? [...prev.statuses, status]
                : prev.statuses.filter(s => s !== status);
            return { ...prev, statuses: newStatuses };
        });
    };

    const handleApply = () => {
        onApply(localFilters);
        onClose();
    };

    const handleClear = () => {
        onClear();
        onClose();
    };

    return (
        <>
            {isOpen && <div className="fixed inset-0 bg-black/60 z-[59]" onClick={onClose} aria-hidden="true" />}
            <div className={`fixed top-0 right-0 h-full w-full max-w-sm bg-[#f8f8f8] dark:bg-slate-800 shadow-2xl z-[60] transform transition-transform duration-300 ease-in-out flex flex-col ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}>
                <div className="flex items-center justify-between p-4 border-b border-gray-200 dark:border-slate-700 flex-shrink-0">
                    <h2 id="filter-panel-title" className="text-lg font-semibold text-[#293c51] dark:text-gray-100 flex items-center">
                        <Icon name="fas fa-filter" className="mr-2" />
                        Filter SMTP Logs
                    </h2>
                    <button onClick={onClose} className="p-2 rounded-full text-gray-500 hover:bg-gray-200 dark:text-gray-400 dark:hover:bg-slate-700" aria-label="Close filters">
                        <Icon name="fas fa-times" className="text-xl" />
                    </button>
                </div>

                <div className="flex-grow overflow-y-auto p-4 space-y-4">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FormField id="from" name="from" label="Email From" value={localFilters.from} onChange={handleLocalChange} placeholder="user@example.com" />
                        <FormField id="to" name="to" label="Email To" value={localFilters.to} onChange={handleLocalChange} placeholder="recipient@example.com" />
                    </div>
                    <FormField id="subject" name="subject" label="Subject" value={localFilters.subject} onChange={handleLocalChange} placeholder="e.g., Invoice, Report" />
                    <FormField as="select" id="action" name="action" label="Action" value={localFilters.action} onChange={handleLocalChange}>
                        <option value="ALL">All Actions</option>
                        {SMTP_ACTIONS.map(action => <option key={action} value={action}>{action}</option>)}
                    </FormField>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <FormField id="dateFrom" name="dateFrom" label="Date From" type="date" value={localFilters.dateFrom} onChange={handleLocalChange} />
                        <FormField id="dateTo" name="dateTo" label="Date To" type="date" value={localFilters.dateTo} onChange={handleLocalChange} />
                    </div>

                    <CollapsibleSection title="Filter by Status" initialOpen={true}>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-4 gap-y-2 pt-2">
                            {SMTP_STATUSES.map(status => (
                                <FormField
                                    key={status}
                                    type="checkbox"
                                    id={`status-${status}`}
                                    name={status}
                                    label={status}
                                    checked={localFilters.statuses.includes(status)}
                                    onChange={(e) => handleStatusChange(status, (e.target as HTMLInputElement).checked)}
                                />
                            ))}
                        </div>
                    </CollapsibleSection>
                </div>

                <div className="flex-shrink-0 p-4 border-t border-gray-200 dark:border-slate-700 bg-white dark:bg-slate-800 space-x-2 flex justify-end">
                    <Button variant="outline" onClick={handleClear}>Clear Filters</Button>
                    <Button onClick={handleApply}>Apply Filters</Button>
                </div>
            </div>
        </>
    );
};

