            const result = [];
            for (let i = 0; i < days; i++) {
                const baseVal = base[i % base.length] * domainMultiplier;
                result.push(Math.max(0, Math.floor(baseVal + Math.floor(Math.random() * (400 * domainMultiplier)) - (200 * domainMultiplier))));
