                                    </div>
                                )}

                                <div className="pt-4 mt-2">
                                    {config.billingMode === 'payg_wallet' && (
                                        <div className={`p-4 rounded-xl mb-4 text-center transition-colors ${grandTotal > walletBalance ? 'bg-red-50 dark:bg-red-900/20 border border-red-200' : 'bg-blue-50 dark:bg-sky-900/10 border border-blue-100'}`}>
                                            <p className="text-[10px] text-gray-500 uppercase font-bold">Wallet Availability</p>
                                            <p className={`text-xl font-bold mt-1 ${grandTotal > walletBalance ? 'text-red-600' : 'text-[#293c51] dark:text-white'}`}>
                                                ${walletBalance.toFixed(2)}
                                            </p>
                                            {grandTotal > walletBalance && (
                                                <button type="button" onClick={() => setIsTopUpModalOpen(true)} className="text-xs text-red-700 dark:text-red-400 font-bold underline mt-2 hover:no-underline">
                                                    Top Up Required
                                                </button>
                                            )}
                                        </div>
                                    )}

                                    <Button 
                                        fullWidth 
                                        size="lg" 
                                        onClick={handleSave}
                                        disabled={!config.name || (config.billingMode === 'payg_wallet' && grandTotal > walletBalance)}
                                        className="shadow-lg shadow-green-500/20"
                                    >
                                        {isEditing ? 'Save Changes' : (config.quantity! > 1 ? 'Configure Multi-Deployment' : 'Review & Deploy')}
                                    </Button>
                                </div>
                            </div>
                        </Card>
                    </div>
                </div>
            ) : (
                /* STEP 2: BULK NAMING */
                <Card className="max-w-2xl mx-auto animate-fade-in">
                    <div className="p-6">
                        <h3 className="text-xl font-bold mb-2">Identify Your Instances</h3>
                        <p className="text-sm text-gray-500 mb-6">Give each of your {config.quantity} nodes a unique identifier.</p>
                        <div className="space-y-4 max-h-[50vh] overflow-y-auto pr-2">
                            {individualNames.map((name, idx) => (
                                <FormField 
                                    key={idx}
                                    id={`name-${idx}`}
                                    label={`Instance #${idx + 1}`}
                                    value={name}
                                    onChange={e => {
                                        const newNames = [...individualNames];
                                        newNames[idx] = e.target.value;
                                        setIndividualNames(newNames);
                                    }}
                                    required
                                />
                            ))}
                        </div>
                        <div className="mt-8 pt-6 border-t flex justify-end gap-3">
                            <Button variant="ghost" onClick={() => setPageStep(1)}>Back</Button>
                            {/* Fix: handleFinalSubmit correctly defined */}
                            <Button onClick={handleFinalSubmit}>Create All Configurations</Button>
                        </div>
                    </div>
                </Card>
            )}

            {/* Fix: Added missing Modal state and logic for Wallet Top Up */}
            <Modal 
                isOpen={isTopUpModalOpen} 
                onClose={() => setIsTopUpModalOpen(false)} 
                title="Top Up Wallet" 
                size="sm"
            >
                <div className="space-y-4">
                    <p className="text-sm text-gray-600">Ensure your wallet has enough funds for the initial deployment period.</p>
                    {/* Fix: Bound FormField to state with onChange */}
                    <FormField 
                        id="topup-amt" 
                        label="Amount (USD)" 
                        type="number" 
                        placeholder="50.00" 
                        value={modalTopUpAmount}
                        onChange={(e) => setModalTopUpAmount(parseFloat(e.target.value) || '')}
                    />
                    {/* Fix: handleTopUp and Modal closing logic added */}
                    <Button fullWidth onClick={() => { 
                        const amount = typeof modalTopUpAmount === 'number' ? modalTopUpAmount : 50;
                        handleTopUp(amount); 
                        setIsTopUpModalOpen(false); 
                    }}>Add ${modalTopUpAmount || '50.00'}</Button>
                </div>
            </Modal>
        </div>
    );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Button, Card, FormField, CollapsibleSection, SliderInput, Icon, Modal, Tooltip, ToggleSwitch } from '@/components/ui';
import type { CloudEdgeConfiguration, InstanceTemplate, CloudEdgeComponentType, MachineType } from '@/types';
import { v4 as uuidv4 } from 'uuid';
import { useNavigate, useParams, Link, useLocation } from 'react-router-dom';

const CONFIG_STORAGE_KEY = 'cloudEdgeConfigurations';
const WALLET_STORAGE_KEY = 'cloudEdgeWalletBalanceUSD';

// --- PRICING CONSTANTS ---
const PRICE_H100_SLICE_12GB_MONTHLY = 120.00;
const H100_SLICE_OPTIONS = [1, 2, 4, 8];

const mockTeslaGpuOptions = [
  { id: 'tesla-1x12', label: '1 card, 12 GB', priceMonthly: 150.00 },
  { id: 'tesla-1x24', label: '1 card, 24 GB', priceMonthly: 280.00 },
  { id: 'tesla-2x24', label: '2 cards, 24 GB', priceMonthly: 500.00 },
];

const PRICE_CPU_CORE_MONTHLY = 10;
const PRICE_RAM_GB_MONTHLY = 5;
const PRICE_FLASH_GB_MONTHLY = 0.10;
const PRICE_FLASH_DISK_SSD_GB_MONTHLY = 0.15;
const PRICE_FLASH_DISK_NVME_GB_MONTHLY = 0.30;

// --- MOCK OPTIONS ---
const mockRegions = [
    { id: 'eu-central-1', name: 'EU (Frankfurt)', flag: '🇩🇪' },
    { id: 'us-east-1', name: 'EU (Strasbourg)', flag: '🇫🇷' },
];

const mockInstanceTemplates: InstanceTemplate[] = [
  { id: 'ce-s1', name: 'Micro (CE-S1)', cpu: 2, ramGB: 4, bootDiskGB: 50, priceMonthly: 20, description: 'Best for web proxies & lightweight apps' },
  { id: 'ce-m1', name: 'Standard (CE-M1)', cpu: 4, ramGB: 8, bootDiskGB: 100, priceMonthly: 40, description: 'Production balanced workloads' },
  { id: 'ce-l1', name: 'Power (CE-L1)', cpu: 8, ramGB: 16, bootDiskGB: 200, priceMonthly: 80, description: 'Demanding databases & analytics' },
];

const topOsChoices = [
    { id: 'ubuntu-22', name: 'Ubuntu 22.04 LTS', icon: 'fab fa-ubuntu' },
    { id: 'windows-2022-std', name: 'Windows 2022', icon: 'fab fa-windows' },
    { id: 'centos-9', name: 'CentOS 9', icon: 'fab fa-centos' },
];

interface ReadyPlan {
  id: string;
  name: string;
  description: string;
  priceMonthly: number;
}

const mockReadyPlans: ReadyPlan[] = [
    { id: 'rp-dev', name: 'Dev Sandbox', description: '1 vCPU, 2GB RAM, 40GB SSD', priceMonthly: 15 },
    { id: 'rp-web', name: 'Web Cluster', description: '4 vCPU, 8GB RAM, 100GB SSD', priceMonthly: 50 },
];

// --- HELPER COMPONENTS ---

const VisualCard = ({ active, onClick, icon, title, description, price }: any) => (
    <div 
        onClick={onClick}
        className={`cursor-pointer flex flex-col p-5 border-2 rounded-xl transition-all duration-200 ${
            active 
            ? 'border-[#679a41] bg-green-50/50 dark:bg-emerald-900/10 ring-1 ring-[#679a41]' 
            : 'border-gray-200 dark:border-slate-700 hover:border-gray-300 dark:hover:border-slate-600 bg-white dark:bg-slate-800'
        }`}
    >
        <div className="flex justify-between items-start mb-3">
            <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${active ? 'bg-[#679a41] text-white' : 'bg-gray-100 dark:bg-slate-700 text-gray-500'}`}>
                <Icon name={icon} className="text-xl" />
            </div>
            {price && <span className="font-bold text-[#679a41] dark:text-emerald-400">${price}<small className="font-normal opacity-70">/mo</small></span>}
        </div>
        <h4 className={`font-bold text-sm ${active ? 'text-[#293c51] dark:text-white' : 'text-gray-700 dark:text-gray-300'}`}>{title}</h4>
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1 leading-relaxed">{description}</p>
    </div>
);

const PriceBreakdownRow = ({ label, value }: { label: string, value: string | number }) => (
    <div className="flex justify-between items-center text-sm py-1">
        <span className="text-gray-500 dark:text-gray-400">{label}</span>
        <span className="font-semibold text-[#293c51] dark:text-gray-100">{value}</span>
    </div>
);

// --- MAIN CONFIGURATOR ---

export const AddCloudEdgeConfigurationPage: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { configId } = useParams<{ configId: string }>();
    const isEditing = !!configId;

    const initialBillingMode = (location.state as any)?.initialBillingMode || 'payg_wallet';

    const [walletBalance, setWalletBalance] = useState<number>(0);
    const [pageStep, setPageStep] = useState(1);
    const [individualNames, setIndividualNames] = useState<string[]>([]);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [modalTopUpAmount, setModalTopUpAmount] = useState<number | ''>('');

    const [config, setConfig] = useState<Partial<CloudEdgeConfiguration>>({
        type: 'instance',
        quantity: 1,
        deploymentRegion: 'eu-central-1',
        billingMode: initialBillingMode,
        machineType: 'Type I',
        instanceTemplateId: 'ce-s1',
        expectedRuntimeHours: 730,
        gpuEnabled: false,
        gpuFamily: 'h100',
        h100Slices: 1,
        flashDiskEnabled: false,
        flashDiskType: 'SSD',
        flashDiskGB: 0,
        subscriptionTermValue: 1,
        subscriptionTermUnit: 'month'
    });

    useEffect(() => {
        const savedBalance = localStorage.getItem(WALLET_STORAGE_KEY);
        setWalletBalance(savedBalance ? parseFloat(savedBalance) : 200.00);

        if (isEditing) {
            const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
            if (saved) {
                const found = JSON.parse(saved).find((c: any) => c.id === configId);
                if (found) setConfig(found);
            }
        }
    }, [configId, isEditing]);

    const handleTopUp = (amount: number) => {
        const newBalance = walletBalance + amount;
        setWalletBalance(newBalance);
        localStorage.setItem(WALLET_STORAGE_KEY, newBalance.toString());
        alert(`Success! $${amount.toFixed(2)} has been added to your wallet.`);
    };

    const handleFinalSubmit = () => {
        finalizeSave(individualNames);
    };

    const calculateSubtotal = useCallback(() => {
        let total = 0;
        if (config.type === 'instance') {
            const tpl = mockInstanceTemplates.find(t => t.id === config.instanceTemplateId);
            if (tpl) total += tpl.priceMonthly;
        } else if (config.type === 'vdc') {
            total += (config.vdcCPU || 0) * PRICE_CPU_CORE_MONTHLY;
            total += (config.vdcRAM || 0) * PRICE_RAM_GB_MONTHLY;
            total += (config.vdcFlashStorage || 0) * PRICE_FLASH_GB_MONTHLY;
        } else {
            total += mockReadyPlans.find(p => p.id === config.readyPlanId)?.priceMonthly || 0;
        }

        if (config.gpuEnabled) {
            if (config.gpuFamily === 'tesla') {
                total += mockTeslaGpuOptions.find(o => o.id === config.teslaOptionId)?.priceMonthly || 0;
            } else {
                total += (config.h100Slices || 0) * PRICE_H100_SLICE_12GB_MONTHLY;
            }
        }

        if (config.flashDiskEnabled) {
            const rate = config.flashDiskType === 'NVMe' ? PRICE_FLASH_DISK_NVME_GB_MONTHLY : PRICE_FLASH_DISK_SSD_GB_MONTHLY;
            total += (config.flashDiskGB || 0) * rate;
        }

        if (config.billingMode === 'payg_wallet' && config.type === 'instance') {
            const hourly = total / 730;
            return hourly * (config.expectedRuntimeHours || 730);
        }

        return total;
    }, [config]);

    const subtotal = useMemo(() => calculateSubtotal(), [calculateSubtotal]);
    const grandTotal = subtotal * (config.quantity || 1);

    const handleUpdate = (updates: Partial<CloudEdgeConfiguration>) => {
        setConfig(prev => ({ ...prev, ...updates }));
    };

    const handleSave = () => {
        if (!config.name) { alert("Please name your configuration."); return; }

        if ((config.quantity || 1) > 1 && !isEditing) {
            setIndividualNames(Array.from({ length: config.quantity! }, (_, i) => `${config.name}-${i + 1}`));
            setPageStep(2);
        } else {
            finalizeSave(individualNames.length > 0 ? individualNames : [config.name!]);
        }
    };

    const finalizeSave = (names: string[]) => {
        const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
        const existing = saved ? JSON.parse(saved) : [];

        const newConfigs = names.map(name => ({
            ...config,
            id: isEditing ? configId : uuidv4(),
            name,
            quantity: 1,
            unitSubtotalMonthly: subtotal,
            creationDate: new Date().toISOString()
        }));

        const updated = isEditing 
            ? existing.map((c: any) => c.id === configId ? newConfigs[0] : c)
            : [...existing, ...newConfigs];

