// --- MAIN CONFIGURATOR ---

export const AddCloudEdgeConfigurationPage: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { configId } = useParams<{ configId: string }>();
    const isEditing = !!configId;

    const initialBillingMode = (location.state as any)?.initialBillingMode || 'payg_wallet';

    const [walletBalance, setWalletBalance] = useState<number>(0);
    const [pageStep, setPageStep] = useState(1);
    const [individualNames, setIndividualNames] = useState<string[]>([]);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [modalTopUpAmount, setModalTopUpAmount] = useState<number | ''>('');

    const [config, setConfig] = useState<Partial<CloudEdgeConfiguration>>({
        type: 'instance',
        quantity: 1,
        deploymentRegion: 'eu-central-1',
        billingMode: initialBillingMode,
        machineType: 'Type I',
        instanceTemplateId: 'ce-s1',
        readyPlanId: 'rp-starter',
        expectedRuntimeHours: 730,
        gpuEnabled: false,
        gpuFamily: 'h100',
        h100Slices: 1,
        flashDiskEnabled: false,
        flashDiskType: 'SSD',
        flashDiskGB: 0,
        subscriptionTermValue: 1,
        subscriptionTermUnit: 'month'
    });

    useEffect(() => {
        const savedBalance = localStorage.getItem(WALLET_STORAGE_KEY);
        setWalletBalance(savedBalance ? parseFloat(savedBalance) : 200.00);

        if (isEditing) {
            const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
            if (saved) {
                const found = JSON.parse(saved).find((c: any) => c.id === configId);
                if (found) setConfig(found);
            }
        }
    }, [configId, isEditing]);

    const handleTopUp = (amount: number) => {
        const newBalance = walletBalance + amount;
        setWalletBalance(newBalance);
        localStorage.setItem(WALLET_STORAGE_KEY, newBalance.toString());
        alert(`Success! $${amount.toFixed(2)} has been added to your wallet.`);
    };

    const handleFinalSubmit = () => {
        finalizeSave(individualNames);
    };

    const calculateSubtotal = useCallback(() => {
        let total = 0;
        if (config.type === 'instance') {
            const tpl = mockInstanceTemplates.find(t => t.id === config.instanceTemplateId);
            if (tpl) total += tpl.priceMonthly;

            // GPU is only allowed for Instance types
            if (config.gpuEnabled) {
                if (config.gpuFamily === 'tesla') {
                    total += mockTeslaGpuOptions.find(o => o.id === config.teslaOptionId)?.priceMonthly || 0;
                } else {
                    total += (config.h100Slices || 0) * PRICE_H100_SLICE_12GB_MONTHLY;
                }
            }
        } else if (config.type === 'vdc') {
            total += (config.vdcCPU || 0) * PRICE_CPU_CORE_MONTHLY;
            total += (config.vdcRAM || 0) * PRICE_RAM_GB_MONTHLY;
            total += (config.vdcFlashStorage || 0) * PRICE_FLASH_GB_MONTHLY;
        } else {
            total += mockReadyPlans.find(p => p.id === config.readyPlanId)?.priceMonthly || 0;
        }

        if (config.flashDiskEnabled) {
            const rate = config.flashDiskType === 'NVMe' ? PRICE_FLASH_DISK_NVME_GB_MONTHLY : PRICE_FLASH_DISK_SSD_GB_MONTHLY;
            total += (config.flashDiskGB || 0) * rate;
        }

        if (config.billingMode === 'payg_wallet' && config.type === 'instance') {
            const hourly = total / 730;
            return hourly * (config.expectedRuntimeHours || 730);
        }

        return total;
    }, [config]);

    const subtotal = useMemo(() => calculateSubtotal(), [calculateSubtotal]);
    const grandTotal = subtotal * (config.quantity || 1);

    const handleUpdate = (updates: Partial<CloudEdgeConfiguration>) => {
        setConfig(prev => ({ ...prev, ...updates }));
    };

    const handleSave = () => {
        if (!config.name) { alert("Please name your configuration."); return; }

        if ((config.quantity || 1) > 1 && !isEditing) {
            setIndividualNames(Array.from({ length: config.quantity! }, (_, i) => `${config.name}-${i + 1}`));
            setPageStep(2);
        } else {
            finalizeSave(individualNames.length > 0 ? individualNames : [config.name!]);
        }
    };

    const finalizeSave = (names: string[]) => {
        const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
        const existing = saved ? JSON.parse(saved) : [];

        const newConfigs = names.map(name => ({
            ...config,
            id: isEditing ? configId : uuidv4(),
            name,
            quantity: 1,
            unitSubtotalMonthly: subtotal,
            creationDate: new Date().toISOString()
        }));

        const updated = isEditing 
            ? existing.map((c: any) => c.id === configId ? newConfigs[0] : c)
            : [...existing, ...newConfigs];

        localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(updated));
        navigate('/app/billing/cloudedge-configurations');
    };

    return (
        <div className="max-w-7xl mx-auto space-y-6 animate-fade-in">
            <header className="flex justify-between items-center pb-4 border-b dark:border-slate-700">
                <div>
                    <h1 className="text-2xl font-bold text-[#293c51] dark:text-gray-100">
                        {isEditing ? 'Edit Configuration' : 'Deploy New Infrastructure'}
                    </h1>
                    <p className="text-sm text-gray-500">Configure your high-performance CloudEdge resources.</p>
                </div>
                <Button variant="ghost" onClick={() => navigate(-1)} leftIconName="fas fa-arrow-left">Cancel</Button>
            </header>

            {pageStep === 1 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* LEFT PANEL: CONFIGURATOR */}
                    <div className="lg:col-span-8 space-y-8">
                        {/* Step 1: Base Type */}
                        <section>
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">1</span>
                                Choose Resource Model
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <VisualCard 
                                    active={config.type === 'instance'}
                                    onClick={() => handleUpdate({ type: 'instance' })}
                                    icon="fas fa-server"
                                    title="Standard Instances"
                                    description="Scalable virtual machines for apps and databases."
                                />
                                <VisualCard 
                                    active={config.type === 'vdc'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'vdc', billingMode: 'subscription' })}
                                    icon="fas fa-cloud"
                                    title="Virtual Data Center"
                                    description="Custom resource pool with isolated networking."
                                />
                                <VisualCard 
                                    active={config.type === 'ready-plan'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'ready-plan', billingMode: 'subscription' })}
                                    icon="fas fa-bolt"
                                    title="Ready Plans"
                                    description="One-click optimized pre-configurations."
                                />
                            </div>
                        </section>

                        {/* Step 2: Primary Specs */}
                        <section className="space-y-6">
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">2</span>
                                Configuration Details
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-2">
                                <FormField id="configName" label="Configuration Name" value={config.name || ''} onChange={e => handleUpdate({ name: e.target.value })} placeholder="e.g. Prod-Web-Cluster" required />
                                <FormField id="region" label="Deployment Region" as="select" value={config.deploymentRegion} onChange={e => handleUpdate({ deploymentRegion: e.target.value })}>
                                    {mockRegions.map(r => <option key={r.id} value={r.id}>{r.flag} {r.name}</option>)}
                                </FormField>
                                {config.billingMode === 'subscription' && (
                                    <>
                                        <FormField 
                                            id="subTerm" 
                                            label="Subscription Term" 
                                            type="number" 
                                            value={config.subscriptionTermValue || 1} 
                                            onChange={e => handleUpdate({ subscriptionTermValue: parseInt(e.target.value) || 1 })} 
                                            min={1} 
                                        />
                                        <FormField 
                                            id="subUnit" 
                                            label="Duration Unit" 
                                            as="select" 
                                            value={config.subscriptionTermUnit} 
                                            onChange={e => handleUpdate({ subscriptionTermUnit: e.target.value as any })}
                                        >
                                            <option value="month">Month(s)</option>
                                            <option value="year">Year(s)</option>
                                        </FormField>
                                    </>
                                )}
                                {config.billingMode === 'payg_wallet' && config.type === 'instance' && (
                                     <FormField 
                                        id="runtime" 
                                        label="Est. Monthly Runtime (Hours)" 
                                        type="number" 
                                        value={config.expectedRuntimeHours || 730} 
                                        onChange={e => handleUpdate({ expectedRuntimeHours: parseInt(e.target.value) || 0 })} 
                                        min={1} 
                                        max={730}
                                        hint="Average month has 730 hours. Used for price estimation only."
                                    />
                                )}
                            </div>

                            {config.type === 'instance' && (
                                <Card className="!bg-gray-50 dark:!bg-slate-900/40 border-none">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {mockInstanceTemplates.map(t => (
                                            <VisualCard 
                                                key={t.id}
                                                active={config.instanceTemplateId === t.id}
                                                onClick={() => handleUpdate({ instanceTemplateId: t.id })}
                                                icon="fas fa-microchip"
                                                title={t.name}
                                                price={t.priceMonthly}
                                                description={t.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-6 items-end">
                                        <FormField id="tier" label="Infrastructure Tier" as="select" value={config.machineType} onChange={e => handleUpdate({ machineType: e.target.value as MachineType })}>
                                            <option value="Type I">Type I (Shared Resources)</option>
                                            <option value="Type II">Type II (Dedicated Resources)</option>
                                        </FormField>
                                        <FormField id="qty" label="Total Nodes" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </Card>
                            )}

                            {config.type === 'vdc' && (
                                <Card className="space-y-6">
                                    <SliderInput id="cpu" label="CPU Cores" value={config.vdcCPU || 4} onChange={v => handleUpdate({ vdcCPU: v })} min={2} max={64} step={1} unit="Cores" />
                                    <SliderInput id="ram" label="System RAM" value={config.vdcRAM || 8} onChange={v => handleUpdate({ vdcRAM: v })} min={4} max={256} step={4} unit="GB" />
                                    <SliderInput id="storage" label="Boot Storage" value={config.vdcFlashStorage || 100} onChange={v => handleUpdate({ vdcFlashStorage: v })} min={50} max={5000} step={50} unit="GB" />
                                </Card>
                            )}

                            {config.type === 'ready-plan' && (
                                <Card className="!bg-gray-50 dark:!bg-slate-900/40 border-none">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {mockReadyPlans.map(p => (
                                            <VisualCard 
                                                key={p.id}
                                                active={config.readyPlanId === p.id}
                                                onClick={() => handleUpdate({ readyPlanId: p.id })}
                                                icon="fas fa-layer-group"
                                                title={p.name}
                                                price={p.priceMonthly}
                                                description={p.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="mt-6">
                                        <FormField id="qty-rp" label="Total Nodes" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </Card>
                            )}
                        </section>

                        {/* Step 3: Performance & Options */}
                        <section className="space-y-4">
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">3</span>
                                Acceleration & Storage
                            </h3>

                            {config.type === 'instance' && (
                                <CollapsibleSection title="GPU Acceleration (H100 & Tesla)" initialOpen={config.gpuEnabled}>
                                    <div className="space-y-4 pt-2">
                                        <div className="flex justify-between items-center p-4 bg-gray-50 dark:bg-slate-800/50 rounded-xl">
                                            <div>
                                                <p className="font-bold text-sm">Enable GPU</p>
                                                <p className="text-xs text-gray-500">Only available for Type II Infrastructure.</p>
                                            </div>
                                            <ToggleSwitch id="gpu" checked={!!config.gpuEnabled} onChange={v => handleUpdate({ gpuEnabled: v })} disabled={config.machineType === 'Type I'} />
                                        </div>
                                        {config.gpuEnabled && (
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 animate-fade-in">
                                                <FormField id="family" label="GPU Family" as="select" value={config.gpuFamily} onChange={e => handleUpdate({ gpuFamily: e.target.value as any })}>
                                                    <option value="h100">NVIDIA H100 (Slices)</option>
                                                    <option value="tesla">NVIDIA Tesla (Bundles)</option>
                                                </FormField>
                                                {config.gpuFamily === 'h100' ? (
                                                    <FormField id="slices" label="Allocated Slices" as="select" value={config.h100Slices} onChange={e => handleUpdate({ h100Slices: parseInt(e.target.value) })}>
                                                        {H100_SLICE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt} Slice ({opt * 12}GB VRAM)</option>)}
                                                    </FormField>
                                                ) : (
                                                    <FormField id="tesla" label="Tesla Bundle" as="select" value={config.teslaOptionId} onChange={e => handleUpdate({ teslaOptionId: e.target.value })}>
                                                        <option value="">Select card bundle...</option>
                                                        {mockTeslaGpuOptions.map(o => <option key={o.id} value={o.id}>{o.label}</option>)}
                                                    </FormField>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                </CollapsibleSection>
                            )}

                            <CollapsibleSection title="Operating System & Software" initialOpen={true}>
                                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 pt-2">
                                    {topOsChoices.map(os => (
                                        <button 
                                            key={os.id} 
                                            type="button"
                                            onClick={() => handleUpdate({ osSoftware: os.id })}
                                            className={`flex items-center gap-3 p-3 border rounded-lg transition-all ${config.osSoftware === os.id ? 'border-[#679a41] bg-green-50 dark:bg-emerald-900/20' : 'hover:border-gray-400'}`}
                                        >
                                            <Icon name={os.icon} className="text-xl text-gray-500" />
                                            <span className="text-sm font-medium">{os.name}</span>
                                        </button>
                                    ))}
                                    <Link to="/app/billing/cloudedge-configurations/os-images" className="flex items-center justify-center p-3 border border-dashed rounded-lg text-xs text-sky-600 hover:bg-sky-50 transition-colors">
                                        View All Images
                                    </Link>
                                </div>
                            </CollapsibleSection>

                            <CollapsibleSection title="Secondary Flash Disk (Expansion)">
                                <div className="space-y-4 pt-2">
                                    <div className="flex justify-between items-center p-4 bg-gray-50 dark:bg-slate-800/50 rounded-xl">
                                        <span className="text-sm font-bold">Add Dedicated Disk</span>
                                        <ToggleSwitch id="fdisk" checked={!!config.flashDiskEnabled} onChange={v => handleUpdate({ flashDiskEnabled: v })} />
                                    </div>
                                    {config.flashDiskEnabled && (
                                        <div className="animate-fade-in space-y-4">
                                            <FormField id="dtype" label="Disk Type" as="select" value={config.flashDiskType} onChange={e => handleUpdate({ flashDiskType: e.target.value as any })}>
                                                <option value="SSD">Standard SSD</option>
                                                <option value="NVMe">High Performance NVMe</option>
                                            </FormField>
                                            <SliderInput id="fsize" label="Capacity" value={config.flashDiskGB || 0} onChange={v => handleUpdate({ flashDiskGB: v })} min={0} max={2000} step={50} unit="GB" />
                                        </div>
                                    )}
                                </div>
                            </CollapsibleSection>
                        </section>
                    </div>

                    {/* RIGHT PANEL: SUMMARY & EXECUTION */}
                    <div className="lg:col-span-4 space-y-6">
                        <Card className="sticky top-20 border-2 border-gray-100 dark:border-slate-700 shadow-sm">
                            <h3 className="text-lg font-bold mb-4 pb-2 border-b">Estimate Summary</h3>
                            <div className="space-y-4">
                                <div className="space-y-1">
                                    <PriceBreakdownRow label="Infrastructure Tier" value={config.machineType || '-'} />
                                    <PriceBreakdownRow label="Resource Model" value={config.type || '-'} />
                                    <PriceBreakdownRow label="Region" value={mockRegions.find(r => r.id === config.deploymentRegion)?.name || '-'} />
                                    <PriceBreakdownRow label="Billing Mode" value={config.billingMode === 'payg_wallet' ? 'PAYG (Hourly)' : 'Subscription'} />
                                    {config.billingMode === 'subscription' && (
                                        <PriceBreakdownRow label="Term" value={`${config.subscriptionTermValue} ${config.subscriptionTermUnit}${config.subscriptionTermValue! > 1 ? 's' : ''}`} />
                                    )}
                                </div>

                                <div className="pt-4 border-t dark:border-slate-700">
                                    <div className="flex justify-between items-end mb-2">
                                        <span className="text-sm font-medium">Unit Subtotal</span>
                                        <span className="text-2xl font-bold text-[#679a41] dark:text-emerald-400">${subtotal.toFixed(2)}</span>
                                    </div>
                                    <p className="text-[10px] text-gray-400 text-right uppercase tracking-wider font-bold">Per month / per instance</p>
                                </div>

                                {config.quantity! > 1 && (
                                    <div className="flex justify-between items-center pt-2 text-gray-600 dark:text-gray-400">
                                        <span className="text-sm">Combined (x{config.quantity})</span>
                                        <span className="font-bold">${grandTotal.toFixed(2)}</span>
                                    </div>
                                )}

                                <div className="pt-4 mt-2">
                                    {config.billingMode === 'payg_wallet' && (
                                        <div className={`p-4 rounded-xl mb-4 text-center transition-colors ${grandTotal > walletBalance ? 'bg-red-50 dark:bg-red-900/20 border border-red-200' : 'bg-blue-50 dark:bg-sky-900/10 border border-blue-100'}`}>
                                            <p className="text-[10px] text-gray-500 uppercase font-bold">Wallet Availability</p>
                                            <p className={`text-xl font-bold mt-1 ${grandTotal > walletBalance ? 'text-red-600' : 'text-[#293c51] dark:text-white'}`}>
                                                ${walletBalance.toFixed(2)}
                                            </p>
                                            {grandTotal > walletBalance && (
                                                <button type="button" onClick={() => setIsTopUpModalOpen(true)} className="text-xs text-red-700 dark:text-red-400 font-bold underline mt-2 hover:no-underline">
                                                    Top Up Required
                                                </button>
                                            )}
                                        </div>
                                    )}

                                    <Button 
                                        fullWidth 
                                        size="lg" 
                                        onClick={handleSave}
                                        disabled={!config.name || (config.billingMode === 'payg_wallet' && grandTotal > walletBalance)}
                                        className="shadow-lg shadow-green-500/20"
                                    >
                                        {isEditing ? 'Save Changes' : (config.quantity! > 1 ? 'Configure Multi-Deployment' : 'Review & Deploy')}
                                    </Button>
                                </div>
                            </div>
                        </Card>
                    </div>
                </div>
            ) : (
                /* STEP 2: BULK NAMING */
                <Card className="max-w-2xl mx-auto animate-fade-in shadow-xl">
                    <div className="p-6">
                        <h3 className="text-xl font-bold mb-2">Identify Your Instances</h3>
                        <p className="text-sm text-gray-500 mb-6">Give each of your {config.quantity} nodes a unique identifier.</p>
                        <div className="space-y-4 max-h-[50vh] overflow-y-auto pr-2 custom-scrollbar">
                            {individualNames.map((name, idx) => (
                                <FormField 
                                    key={idx}
                                    id={`name-${idx}`}
                                    label={`Instance #${idx + 1}`}
                                    value={name}
                                    onChange={e => {
                                        const newNames = [...individualNames];
                                        newNames[idx] = e.target.value;
                                        setIndividualNames(newNames);
                                    }}
                                    required
                                />
                            ))}
                        </div>
                        <div className="mt-8 pt-6 border-t flex justify-end gap-3">
                            <Button variant="ghost" onClick={() => setPageStep(1)}>Back</Button>
                            <Button onClick={handleFinalSubmit}>Create All Configurations</Button>
                        </div>
                    </div>
                </Card>
            )}

            <Modal 
                isOpen={isTopUpModalOpen} 
                onClose={() => setIsTopUpModalOpen(false)} 
                title="Top Up Wallet" 
                size="sm"
            >
                <div className="space-y-4">
                    <p className="text-sm text-gray-600 dark:text-gray-400">Ensure your wallet has enough funds for the initial deployment period.</p>
                    <FormField 
                        id="topup-amt" 
                        label="Amount (USD)" 
                        type="number" 
                        placeholder="50.00" 
                        value={modalTopUpAmount}
                        onChange={(e) => setModalTopUpAmount(parseFloat(e.target.value) || '')}
                    />
                    <Button fullWidth onClick={() => { 
                        const amount = typeof modalTopUpAmount === 'number' ? modalTopUpAmount : 50;
                        handleTopUp(amount); 
                        setIsTopUpModalOpen(false); 
                    }}>Add ${modalTopUpAmount || '50.00'}</Button>
                </div>
            </Modal>
        </div>
    );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Button, Card, FormField, CollapsibleSection, SliderInput, Icon, Modal, Tooltip, ToggleSwitch } from '@/components/ui';
import type { CloudEdgeConfiguration, InstanceTemplate, CloudEdgeComponentType, MachineType } from '@/types';
import { v4 as uuidv4 } from 'uuid';
import { useNavigate, useParams, Link, useLocation } from 'react-router-dom';

const CONFIG_STORAGE_KEY = 'cloudEdgeConfigurations';
const WALLET_STORAGE_KEY = 'cloudEdgeWalletBalanceUSD';

// --- PRICING CONSTANTS ---
const PRICE_H100_SLICE_12GB_MONTHLY = 120.00;
const H100_SLICE_OPTIONS = [1, 2, 4, 8];

const mockTeslaGpuOptions = [
  { id: 'tesla-1x12', label: '1 card, 12 GB', priceMonthly: 150.00 },
  { id: 'tesla-1x24', label: '1 card, 24 GB', priceMonthly: 280.00 },
  { id: 'tesla-2x24', label: '2 cards, 24 GB', priceMonthly: 500.00 },
];

const PRICE_CPU_CORE_MONTHLY = 10;
const PRICE_RAM_GB_MONTHLY = 5;
const PRICE_FLASH_GB_MONTHLY = 0.10;
const PRICE_FLASH_DISK_SSD_GB_MONTHLY = 0.15;
const PRICE_FLASH_DISK_NVME_GB_MONTHLY = 0.30;

// --- MOCK OPTIONS ---
const mockRegions = [
    { id: 'eu-central-1', name: 'EU (Frankfurt)', flag: '🇩🇪' },
    { id: 'us-east-1', name: 'EU (Strasbourg)', flag: '🇫🇷' },
];

const mockInstanceTemplates: InstanceTemplate[] = [
  { id: 'ce-s1', name: 'Micro (CE-S1)', cpu: 2, ramGB: 4, bootDiskGB: 50, priceMonthly: 20, description: 'Best for web proxies & lightweight apps' },
  { id: 'ce-m1', name: 'Standard (CE-M1)', cpu: 4, ramGB: 8, bootDiskGB: 100, priceMonthly: 40, description: 'Production balanced workloads' },
  { id: 'ce-l1', name: 'Power (CE-L1)', cpu: 8, ramGB: 16, bootDiskGB: 200, priceMonthly: 80, description: 'Demanding databases & analytics' },
];

interface ReadyPlan {
  id: string;
  name: string;
  description: string;
  priceMonthly: number;
}

const mockReadyPlans: ReadyPlan[] = [
    { id: 'rp-starter', name: 'Starter Node', description: '1 vCPU, 2GB RAM, 40GB SSD', priceMonthly: 15 },
    { id: 'rp-business', name: 'Business Hub', description: '4 vCPU, 8GB RAM, 100GB SSD', priceMonthly: 50 },
    { id: 'rp-enterprise', name: 'Enterprise Core', description: '8 vCPU, 32GB RAM, 500GB NVMe', priceMonthly: 120 },
];

// Fix: Added missing topOsChoices definition
const topOsChoices = [
    { id: 'ubuntu-24', name: 'Ubuntu 24.04 LTS', icon: 'fab fa-ubuntu' },
    { id: 'win-2022', name: 'Windows Server 2022', icon: 'fab fa-windows' },
    { id: 'rhel-9', name: 'RHEL 9', icon: 'fab fa-redhat' },
];

// --- HELPER COMPONENTS ---

interface VisualCardProps {
    active?: boolean;
    disabled?: boolean;
    onClick?: () => void;
    icon: string;
    title: string;
    description: string;
    price?: number;
    statusBadge?: string;
}

const VisualCard = ({ active, disabled, onClick, icon, title, description, price, statusBadge }: VisualCardProps) => (
    <div 
        onClick={!disabled ? onClick : undefined}
        className={`relative flex flex-col p-5 border-2 rounded-xl transition-all duration-200 ${
            disabled 
            ? 'border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/20 opacity-60 grayscale-[0.5] cursor-not-allowed'
            : active 
                ? 'cursor-pointer border-[#679a41] bg-green-50/50 dark:bg-emerald-900/10 ring-1 ring-[#679a41]' 
                : 'cursor-pointer border-gray-200 dark:border-slate-700 hover:border-gray-300 dark:hover:border-slate-600 bg-white dark:bg-slate-800'
        }`}
    >
        {statusBadge && (
            <div className="absolute -top-2.5 right-3 px-2 py-0.5 rounded bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 text-[9px] font-bold uppercase tracking-wider border border-purple-200 dark:border-purple-800">
                {statusBadge}
            </div>
        )}
        <div className="flex justify-between items-start mb-3">
            <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${active ? 'bg-[#679a41] text-white' : 'bg-gray-100 dark:bg-slate-700 text-gray-500'}`}>
                <Icon name={icon} className="text-xl" />
            </div>
            {price && <span className="font-bold text-[#679a41] dark:text-emerald-400">${price}<small className="font-normal opacity-70">/mo</small></span>}
        </div>
        <h4 className={`font-bold text-sm ${active ? 'text-[#293c51] dark:text-white' : 'text-gray-700 dark:text-gray-300'}`}>{title}</h4>
        <p className="text-xs text-gray-500 dark:text-gray-400 mt-1 leading-relaxed">{description}</p>
