const PriceBreakdownRow = ({ label, value }: { label: string, value: string | number }) => (
    <div className="flex justify-between items-center text-sm py-1">
        <span className="text-gray-500 dark:text-gray-400">{label}</span>
        <span className="font-semibold text-[#293c51] dark:text-gray-100">{value}</span>
    </div>
);

// --- MAIN CONFIGURATOR ---

export const AddCloudEdgeConfigurationPage: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { configId } = useParams<{ configId: string }>();
    const isEditing = !!configId;

    const initialBillingMode = (location.state as any)?.initialBillingMode || 'payg_wallet';

    const [walletBalance, setWalletBalance] = useState<number>(0);
    const [pageStep, setPageStep] = useState(1);
    const [individualNames, setIndividualNames] = useState<string[]>([]);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [modalTopUpAmount, setModalTopUpAmount] = useState<number | ''>('');

    const [config, setConfig] = useState<Partial<CloudEdgeConfiguration>>({
        type: 'instance',
        quantity: 1,
        deploymentRegion: 'eu-central-1',
        billingMode: initialBillingMode,
        machineType: 'Type I',
        instanceTemplateId: 'ce-s1',
        readyPlanId: 'rp-starter',
        expectedRuntimeHours: 730,
        gpuEnabled: false,
        gpuFamily: 'h100',
        h100Slices: 1,
        flashDiskEnabled: false,
        flashDiskType: 'SSD',
        flashDiskGB: 0,
        subscriptionTermValue: 1,
        subscriptionTermUnit: 'month'
    });

    useEffect(() => {
        const savedBalance = localStorage.getItem(WALLET_STORAGE_KEY);
        setWalletBalance(savedBalance ? parseFloat(savedBalance) : 200.00);

        if (isEditing) {
            const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
            if (saved) {
                const found = JSON.parse(saved).find((c: any) => c.id === configId);
                if (found) setConfig(found);
            }
        }
    }, [configId, isEditing]);

    const handleTopUp = (amount: number) => {
        const newBalance = walletBalance + amount;
        setWalletBalance(newBalance);
        localStorage.setItem(WALLET_STORAGE_KEY, newBalance.toString());
        alert(`Success! $${amount.toFixed(2)} has been added to your wallet.`);
    };

    const handleFinalSubmit = () => {
        finalizeSave(individualNames);
    };

    const calculateSubtotal = useCallback(() => {
        let total = 0;
        if (config.type === 'instance') {
            const tpl = mockInstanceTemplates.find(t => t.id === config.instanceTemplateId);
            if (tpl) total += tpl.priceMonthly;

            // GPU is only allowed for Instance types
            if (config.gpuEnabled) {
                if (config.gpuFamily === 'tesla') {
                    total += mockTeslaGpuOptions.find(o => o.id === config.teslaOptionId)?.priceMonthly || 0;
                } else {
                    total += (config.h100Slices || 0) * PRICE_H100_SLICE_12GB_MONTHLY;
                }
            }
        } else if (config.type === 'vdc') {
            total += (config.vdcCPU || 0) * PRICE_CPU_CORE_MONTHLY;
            total += (config.vdcRAM || 0) * PRICE_RAM_GB_MONTHLY;
            total += (config.vdcFlashStorage || 0) * PRICE_FLASH_GB_MONTHLY;
        } else {
            total += mockReadyPlans.find(p => p.id === config.readyPlanId)?.priceMonthly || 0;
        }

        if (config.flashDiskEnabled) {
            const rate = config.flashDiskType === 'NVMe' ? PRICE_FLASH_DISK_NVME_GB_MONTHLY : PRICE_FLASH_DISK_SSD_GB_MONTHLY;
            total += (config.flashDiskGB || 0) * rate;
        }

        if (config.billingMode === 'payg_wallet' && config.type === 'instance') {
            const hourly = total / 730;
            return hourly * (config.expectedRuntimeHours || 730);
        }

        return total;
    }, [config]);

    const subtotal = useMemo(() => calculateSubtotal(), [calculateSubtotal]);
    const grandTotal = subtotal * (config.quantity || 1);

    const handleUpdate = (updates: Partial<CloudEdgeConfiguration>) => {
        setConfig(prev => ({ ...prev, ...updates }));
    };

    const handleSave = () => {
        if (!config.name) { alert("Please name your configuration."); return; }

        if ((config.quantity || 1) > 1 && !isEditing) {
            setIndividualNames(Array.from({ length: config.quantity! }, (_, i) => `${config.name}-${i + 1}`));
            setPageStep(2);
        } else {
            finalizeSave(individualNames.length > 0 ? individualNames : [config.name!]);
        }
    };

    const finalizeSave = (names: string[]) => {
        const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
        const existing = saved ? JSON.parse(saved) : [];

        const newConfigs = names.map(name => ({
            ...config,
            id: isEditing ? configId : uuidv4(),
            name,
            quantity: 1,
            unitSubtotalMonthly: subtotal,
            creationDate: new Date().toISOString()
        }));

        const updated = isEditing 
            ? existing.map((c: any) => c.id === configId ? newConfigs[0] : c)
            : [...existing, ...newConfigs];

        localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(updated));
        navigate('/app/billing/cloudedge-configurations');
    };

    return (
        <div className="max-w-7xl mx-auto space-y-6 animate-fade-in">
            <header className="flex justify-between items-center pb-4 border-b dark:border-slate-700">
                <div>
                    <h1 className="text-2xl font-bold text-[#293c51] dark:text-gray-100">
                        {isEditing ? 'Edit Configuration' : 'Deploy New Infrastructure'}
                    </h1>
                    <p className="text-sm text-gray-500">Configure your high-performance CloudEdge resources.</p>
                </div>
                <Button variant="ghost" onClick={() => navigate(-1)} leftIconName="fas fa-arrow-left">Cancel</Button>
            </header>

            {pageStep === 1 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* LEFT PANEL: CONFIGURATOR */}
                    <div className="lg:col-span-8 space-y-8">
                        {/* Step 1: Base Type */}
                        <section>
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">1</span>
                                Choose Resource Model
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                <VisualCard 
                                    active={config.type === 'instance'}
                                    onClick={() => handleUpdate({ type: 'instance' })}
                                    icon="fas fa-server"
                                    title="Standard Instances"
                                    description="Scalable virtual machines for apps and databases."
                                />
                                <VisualCard 
                                    active={config.type === 'vdc'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'vdc', billingMode: 'subscription' })}
                                    icon="fas fa-cloud"
                                    title="Virtual Data Center"
                                    description="Custom resource pool with isolated networking."
                                />
                                <VisualCard 
                                    active={config.type === 'ready-plan'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'ready-plan', billingMode: 'subscription' })}
                                    icon="fas fa-bolt"
                                    title="Ready Plans"
                                    description="One-click optimized pre-configurations."
                                />
                            </div>
                        </section>

                        {/* Step 2: Primary Specs */}
                        <section className="space-y-6">
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">2</span>
                                Configuration Details
                            </h3>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-x-6 gap-y-2">
                                <FormField id="configName" label="Configuration Name" value={config.name || ''} onChange={e => handleUpdate({ name: e.target.value })} placeholder="e.g. Prod-Web-Cluster" required />
                                <FormField id="region" label="Deployment Region" as="select" value={config.deploymentRegion} onChange={e => handleUpdate({ deploymentRegion: e.target.value })}>
                                    {mockRegions.map(r => <option key={r.id} value={r.id}>{r.flag} {r.name}</option>)}
                                </FormField>
                                {config.billingMode === 'subscription' && (
                                    <>
                                        <FormField 
                                            id="subTerm" 
                                            label="Subscription Term" 
                                            type="number" 
                                            value={config.subscriptionTermValue || 1} 
                                            onChange={e => handleUpdate({ subscriptionTermValue: parseInt(e.target.value) || 1 })} 
                                            min={1} 
                                        />
                                        <FormField 
                                            id="subUnit" 
                                            label="Duration Unit" 
                                            as="select" 
                                            value={config.subscriptionTermUnit} 
                                            onChange={e => handleUpdate({ subscriptionTermUnit: e.target.value as any })}
                                        >
                                            <option value="month">Month(s)</option>
                                            <option value="year">Year(s)</option>
                                        </FormField>
                                    </>
                                )}
                                {config.billingMode === 'payg_wallet' && config.type === 'instance' && (
                                     <FormField 
                                        id="runtime" 
                                        label="Est. Monthly Runtime (Hours)" 
                                        type="number" 
                                        value={config.expectedRuntimeHours || 730} 
                                        onChange={e => handleUpdate({ expectedRuntimeHours: parseInt(e.target.value) || 0 })} 
                                        min={1} 
                                        max={730}
                                        hint="Average month has 730 hours. Used for price estimation only."
                                    />
                                )}
                            </div>

                            {config.type === 'instance' && (
                                <Card className="!bg-gray-50 dark:!bg-slate-900/40 border-none">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {mockInstanceTemplates.map(t => (
                                            <VisualCard 
                                                key={t.id}
                                                active={config.instanceTemplateId === t.id}
                                                onClick={() => handleUpdate({ instanceTemplateId: t.id })}
                                                icon="fas fa-microchip"
                                                title={t.name}
                                                price={t.priceMonthly}
                                                description={t.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="mt-6 grid grid-cols-1 md:grid-cols-2 gap-6 items-end">
                                        <FormField id="tier" label="Infrastructure Tier" as="select" value={config.machineType} onChange={e => handleUpdate({ machineType: e.target.value as MachineType })}>
                                            <option value="Type I">Type I (Shared Resources)</option>
                                            <option value="Type II">Type II (Dedicated Resources)</option>
                                        </FormField>
                                        <FormField id="qty" label="Total Nodes" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </Card>
                            )}

                            {config.type === 'vdc' && (
                                <Card className="space-y-6">
                                    <SliderInput id="cpu" label="CPU Cores" value={config.vdcCPU || 4} onChange={v => handleUpdate({ vdcCPU: v })} min={2} max={64} step={1} unit="Cores" />
                                    <SliderInput id="ram" label="System RAM" value={config.vdcRAM || 8} onChange={v => handleUpdate({ vdcRAM: v })} min={4} max={256} step={4} unit="GB" />
                                    <SliderInput id="storage" label="Boot Storage" value={config.vdcFlashStorage || 100} onChange={v => handleUpdate({ vdcFlashStorage: v })} min={50} max={5000} step={50} unit="GB" />
                                </Card>
                            )}

                            {config.type === 'ready-plan' && (
                                <Card className="!bg-gray-50 dark:!bg-slate-900/40 border-none">
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                                        {mockReadyPlans.map(p => (
                                            <VisualCard 
                                                key={p.id}
                                                active={config.readyPlanId === p.id}
                                                onClick={() => handleUpdate({ readyPlanId: p.id })}
                                                icon="fas fa-layer-group"
                                                title={p.name}
                                                price={p.priceMonthly}
                                                description={p.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="mt-6">
                                        <FormField id="qty-rp" label="Total Nodes" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </Card>
                            )}
                        </section>

                        {/* Step 3: Performance & Options */}
                        <section className="space-y-4">
                            <h3 className="text-lg font-bold mb-4 flex items-center gap-2">
                                <span className="bg-[#679a41] text-white w-6 h-6 rounded-full flex items-center justify-center text-xs">3</span>
