                                                    <option value="tesla">NVIDIA Tesla (Bundles)</option>
                                                </FormField>
                                                {config.gpuFamily === 'h100' ? (
                                                    <FormField id="slices" label="Allocated Slices" as="select" value={config.h100Slices} onChange={e => handleUpdate({ h100Slices: parseInt(e.target.value) })}>
