                                    <div className="flex justify-between items-end mb-2">
                                        <span className="text-sm font-medium">Unit Subtotal</span>
                                        <span className="text-2xl font-bold text-[#679a41] dark:text-emerald-400">${subtotal.toFixed(2)}</span>
