                                    <p className="text-[10px] text-gray-400 text-right uppercase tracking-wider font-bold">Per month / per instance</p>
                                </div>

                                {config.quantity! > 1 && (
                                    <div className="flex justify-between items-center pt-2 text-gray-600 dark:text-gray-400">
                                        <span className="text-sm">Combined (x{config.quantity})</span>
                                        <span className="font-bold">${grandTotal.toFixed(2)}</span>
