const VisualCard = ({ active, disabled, onClick, icon, title, description, price, statusBadge, footerText }: VisualCardProps) => (
    <div 
        onClick={!disabled ? onClick : undefined}
        className={`relative flex flex-col p-6 border-2 rounded-2xl transition-all duration-300 group overflow-hidden ${
            disabled 
            ? 'border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/20 opacity-50 grayscale cursor-not-allowed'
            : active 
                ? 'cursor-pointer border-[#679a41] bg-white dark:bg-slate-800 ring-4 ring-[#679a41]/5 shadow-xl transform -translate-y-1' 
                : 'cursor-pointer border-gray-200 dark:border-slate-700 hover:border-[#679a41]/40 hover:bg-gray-50 dark:hover:bg-slate-800/50 bg-white dark:bg-slate-800 shadow-sm'
        }`}
