                        </Card>
                    </div>
                </div>
            ) : (
                /* STEP 2: BULK NAMING */
                <div className="max-w-2xl mx-auto py-20">
                    <Card className="animate-fade-in shadow-[0_50px_100px_rgba(0,0,0,0.15)] overflow-hidden !p-0 rounded-[3rem] border-none bg-white dark:bg-slate-800">
                        <div className="p-12 bg-gradient-to-br from-[#679a41] to-[#588836] text-white">
                            <h3 className="text-3xl font-black mb-2 tracking-tight">Identity Assignment</h3>
                            <p className="text-white/80 font-medium">Assign unique FQDNs or hostnames to your {config.quantity} compute nodes.</p>
                        </div>
                        <div className="p-12 space-y-6 max-h-[55vh] overflow-y-auto custom-scrollbar">
                            {individualNames.map((name, idx) => (
                                <div key={idx} className="flex gap-4 items-end">
                                    <div className="w-12 h-12 rounded-2xl bg-gray-100 dark:bg-slate-700 flex items-center justify-center font-black text-gray-400 flex-shrink-0 mb-4">
                                        {idx + 1}
                                    </div>
                                    <FormField 
                                        id={`name-${idx}`}
                                        label={`Node Label`}
                                        value={name}
                                        onChange={e => {
                                            const newNames = [...individualNames];
                                            newNames[idx] = e.target.value;
                                            setIndividualNames(newNames);
                                        }}
                                        required
                                        placeholder={`vm-cluster-node-0${idx + 1}`}
                                        wrapperClassName="flex-grow"
                                    />
                                </div>
                            ))}
                        </div>
                        <div className="p-12 border-t bg-gray-50 dark:bg-slate-900/50 flex justify-between gap-6">
                            <Button variant="ghost" onClick={() => setPageStep(1)} className="font-bold">Return to Config</Button>
                            <Button onClick={handleFinalSubmit} className="shadow-2xl shadow-green-500/30 px-12 h-14 font-black uppercase tracking-widest rounded-2xl">Initialize Provisioning</Button>
                        </div>
                    </Card>
                </div>
            )}

            <Modal 
                isOpen={isTopUpModalOpen} 
                onClose={() => setIsTopUpModalOpen(false)} 
                title="Secure Wallet Recharge" 
                size="sm"
            >
                <div className="space-y-8 pt-4">
                    <div className="p-5 bg-sky-500/10 dark:bg-sky-500/5 text-sky-700 dark:text-sky-300 text-xs font-bold rounded-2xl flex gap-4 items-start border border-sky-500/20">
                        <Icon name="fas fa-lock" className="mt-1" />
                        <p className="leading-relaxed">All transactions are processed through Stripe Financial Services. Credits are instantly available for resource consumption.</p>
                    </div>
                    <FormField 
                        id="topup-amt" 
                        label="Recharge Value (USD)" 
                        type="number" 
                        placeholder="100.00" 
                        value={modalTopUpAmount}
                        onChange={(e) => setModalTopUpAmount(parseFloat(e.target.value) || '')}
                        inputClassName="text-xl font-black py-4 text-center"
                    />
                    <div className="flex flex-col gap-3">
                         <Button fullWidth onClick={() => { 
                            const amount = typeof modalTopUpAmount === 'number' ? modalTopUpAmount : 50;
                            handleTopUp(amount); 
                            setIsTopUpModalOpen(false); 
                        }} size="lg" className="h-14 font-black uppercase tracking-widest rounded-2xl">Confirm Payment</Button>
                        <Button variant="ghost" fullWidth onClick={() => setIsTopUpModalOpen(false)} className="font-bold text-gray-400">Dismiss</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
};

