export const AddCloudEdgeConfigurationPage: React.FC = () => {
    const navigate = useNavigate();
    const location = useLocation();
    const { configId } = useParams<{ configId: string }>();
    const isEditing = !!configId;

    const initialBillingMode = (location.state as any)?.initialBillingMode || 'payg_wallet';

    const [walletBalance, setWalletBalance] = useState<number>(0);
    const [pageStep, setPageStep] = useState(1);
    const [individualNames, setIndividualNames] = useState<string[]>([]);
    const [isTopUpModalOpen, setIsTopUpModalOpen] = useState(false);
    const [modalTopUpAmount, setModalTopUpAmount] = useState<number | ''>('');

    const [config, setConfig] = useState<Partial<CloudEdgeConfiguration & { nics: string }>>({
        type: 'instance',
        quantity: 1,
        deploymentRegion: 'eu-central-1',
        billingMode: initialBillingMode,
        machineType: 'Type I',
        instanceTemplateId: 'ce-s1',
        readyPlanId: 'rp-starter',
        expectedRuntimeHours: 730,
        gpuEnabled: false,
        gpuFamily: 'h100',
        h100Slices: 1,
        flashDiskEnabled: false,
        flashDiskType: 'SSD',
        flashDiskGB: 0,
        staticPublicIPs: 1,
        objectStorageGB: 0,
        advancedBackupGB: 0,
        nics: '1',
        subscriptionTermValue: 1,
        subscriptionTermUnit: 'month'
    });

    useEffect(() => {
        const savedBalance = localStorage.getItem(WALLET_STORAGE_KEY);
        setWalletBalance(savedBalance ? parseFloat(savedBalance) : 200.00);

        if (isEditing) {
            const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
            if (saved) {
                const found = JSON.parse(saved).find((c: any) => c.id === configId);
                if (found) setConfig(found);
            }
        }
    }, [configId, isEditing]);

    const handleTopUp = (amount: number) => {
        const newBalance = walletBalance + amount;
        setWalletBalance(newBalance);
        localStorage.setItem(WALLET_STORAGE_KEY, newBalance.toString());
    };

    const handleFinalSubmit = () => finalizeSave(individualNames);

    const calculateSubtotal = useCallback(() => {
        let total = 0;
        if (config.type === 'instance') {
            const tpl = mockInstanceTemplates.find(t => t.id === config.instanceTemplateId);
            if (tpl) total += tpl.priceMonthly;

            if (config.gpuEnabled) {
                if (config.gpuFamily === 'tesla') {
                    total += mockTeslaGpuOptions.find(o => o.id === config.teslaOptionId)?.priceMonthly || 0;
                } else {
                    total += (config.h100Slices || 0) * PRICE_H100_SLICE_12GB_MONTHLY;
                }
            }
        } else if (config.type === 'vdc') {
            total += (config.vdcCPU || 0) * PRICE_CPU_CORE_MONTHLY;
            total += (config.vdcRAM || 0) * PRICE_RAM_GB_MONTHLY;
            total += (config.vdcFlashStorage || 0) * PRICE_FLASH_GB_MONTHLY;
        } else {
            total += mockReadyPlans.find(p => p.id === config.readyPlanId)?.priceMonthly || 0;
        }

        total += (config.staticPublicIPs || 0) * PRICE_STATIC_IP_MONTHLY;
        total += (config.objectStorageGB || 0) * PRICE_OBJECT_STORAGE_GB_MONTHLY;
        total += (config.advancedBackupGB || 0) * PRICE_ADVANCED_BACKUP_GB_MONTHLY;

        if (config.flashDiskEnabled) {
            const rate = config.flashDiskType === 'NVMe' ? PRICE_FLASH_DISK_NVME_GB_MONTHLY : PRICE_FLASH_DISK_SSD_GB_MONTHLY;
            total += (config.flashDiskGB || 0) * rate;
        }

        if (config.billingMode === 'payg_wallet' && config.type === 'instance') {
            const hourly = total / 730;
            return hourly * (config.expectedRuntimeHours || 730);
        }

        return total;
    }, [config]);

    const subtotal = useMemo(() => calculateSubtotal(), [calculateSubtotal]);
    const grandTotal = subtotal * (config.quantity || 1);

    const handleUpdate = (updates: Partial<CloudEdgeConfiguration & { nics: string }>) => {
        setConfig(prev => ({ ...prev, ...updates }));
    };

    const handleSave = () => {
        if (!config.name) { alert("Please name your configuration."); return; }
        if ((config.quantity || 1) > 1 && !isEditing) {
            setIndividualNames(Array.from({ length: config.quantity! }, (_, i) => `${config.name}-${i + 1}`));
            setPageStep(2);
        } else {
            finalizeSave(individualNames.length > 0 ? individualNames : [config.name!]);
        }
    };

    const finalizeSave = (names: string[]) => {
        const saved = localStorage.getItem(CONFIG_STORAGE_KEY);
        const existing = saved ? JSON.parse(saved) : [];
        const newConfigs = names.map(name => ({
            ...config,
            id: isEditing ? configId : uuidv4(),
            name,
            quantity: 1,
            unitSubtotalMonthly: subtotal,
            creationDate: new Date().toISOString()
        }));
        const updated = isEditing ? existing.map((c: any) => c.id === configId ? newConfigs[0] : c) : [...existing, ...newConfigs];
        localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(updated));
        navigate('/app/billing/cloudedge-configurations');
    };

    return (
        <div className="max-w-7xl mx-auto space-y-10 animate-fade-in pb-20">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center py-8 border-b-2 border-gray-100 dark:border-slate-800 gap-6">
                <div>
                    <h1 className="text-4xl font-black text-[#293c51] dark:text-gray-100 tracking-tight leading-none">
                        {isEditing ? 'Modify Environment' : 'Provision Architecture'}
                    </h1>
                    <p className="text-base text-gray-500 font-bold uppercase tracking-widest mt-3">High-Availability CloudEdge Infrastructure</p>
                </div>
                <div className="flex items-center gap-4">
                    <Button variant="ghost" onClick={() => navigate(-1)} className="font-bold text-gray-500">
                        <Icon name="fas fa-times" className="mr-2" /> Exit
                    </Button>
                    <div className="h-10 w-px bg-gray-200 dark:bg-slate-800 hidden md:block"></div>
                    <div className="px-5 py-2.5 bg-green-500/10 dark:bg-emerald-500/10 text-[#679a41] dark:text-emerald-400 rounded-2xl text-xs font-black uppercase tracking-widest flex items-center gap-3 border border-[#679a41]/20">
                        <span className="w-2 h-2 rounded-full bg-[#679a41] animate-ping"></span>
                        Real-time Pricing
                    </div>
                </div>
            </header>

            {pageStep === 1 ? (
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
                    {/* LEFT PANEL: CONFIGURATOR */}
                    <div className="lg:col-span-8 space-y-16">
                        {/* Step 1: Base Type */}
                        <section>
                            <SectionHeader step={1} title="Infrastructure Strategy" subtitle="Define the resource provisioning model for your workload." />
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <VisualCard 
                                    active={config.type === 'instance'}
                                    onClick={() => handleUpdate({ type: 'instance' })}
                                    icon="fas fa-microchip"
                                    title="Elastic Compute"
                                    description="Individual virtual instances with fully burstable performance."
                                    footerText="Billed per Node"
                                />
                                <VisualCard 
                                    active={config.type === 'vdc'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'vdc', billingMode: 'subscription' })}
                                    icon="fas fa-project-diagram"
                                    title="Virtual Data Center"
                                    description="Multi-tenant resource pools with isolated software-defined networking."
                                    footerText="Resource Reserved"
                                />
                                <VisualCard 
                                    active={config.type === 'ready-plan'}
                                    disabled={config.billingMode === 'payg_wallet'}
                                    statusBadge={config.billingMode === 'payg_wallet' ? 'Subscription Only' : undefined}
                                    onClick={() => handleUpdate({ type: 'ready-plan', billingMode: 'subscription' })}
                                    icon="fas fa-layer-group"
                                    title="Validated Blueprints"
                                    description="Optimized stacks for databases, dev/test, and high-traffic web apps."
                                    footerText="Zero Configuration"
                                />
                            </div>
                        </section>

                        {/* Step 2: Primary Specs */}
                        <section className="space-y-10">
                            <SectionHeader step={2} title="Environment Specs" subtitle="Naming, location, and hardware configuration details." />

                            <Card className="!p-8 border-gray-100 dark:border-slate-800 shadow-xl bg-white dark:bg-slate-900/50">
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-x-10 gap-y-6">
                                    <FormField id="configName" label="Environment Identity" value={config.name || ''} onChange={e => handleUpdate({ name: e.target.value })} placeholder="e.g. CORE-PROD-CLUSTER" required />
                                    <FormField id="region" label="Deployment Zone" as="select" value={config.deploymentRegion} onChange={e => handleUpdate({ deploymentRegion: e.target.value })}>
                                        {mockRegions.map(r => <option key={r.id} value={r.id}>{r.flag} {r.name}</option>)}
                                    </FormField>

                                    {config.billingMode === 'subscription' && (
                                        <>
                                            <FormField id="subTerm" label="Contract Term" type="number" value={config.subscriptionTermValue || 1} onChange={e => handleUpdate({ subscriptionTermValue: parseInt(e.target.value) || 1 })} min={1} />
                                            <FormField id="subUnit" label="Cycle" as="select" value={config.subscriptionTermUnit} onChange={e => handleUpdate({ subscriptionTermUnit: e.target.value as any })}>
                                                <option value="month">Month(s)</option>
                                                <option value="year">Year(s)</option>
                                            </FormField>
                                        </>
                                    )}

                                    {config.billingMode === 'payg_wallet' && config.type === 'instance' && (
                                        <div className="md:col-span-2">
                                            <FormField id="runtime" label="Estimated Monthly Uptime (Hours)" type="number" value={config.expectedRuntimeHours || 730} onChange={e => handleUpdate({ expectedRuntimeHours: parseInt(e.target.value) || 0 })} min={1} max={730} hint="730 hours = 1 full month. Adjust for dev/test nodes." />
                                        </div>
                                    )}
                                </div>
                            </Card>

                            {config.type === 'instance' && (
                                <div className="space-y-6">
                                    <div className="flex items-center justify-between px-2">
                                        <p className="text-sm font-black text-gray-400 uppercase tracking-widest">Hardware Templates</p>
                                        <Icon name="fas fa-microchip" className="text-gray-300" />
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                        {mockInstanceTemplates.map(t => (
                                            <VisualCard 
                                                key={t.id}
                                                active={config.instanceTemplateId === t.id}
                                                onClick={() => handleUpdate({ instanceTemplateId: t.id })}
                                                icon="fas fa-server"
                                                title={t.name}
                                                price={t.priceMonthly}
                                                description={t.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8 items-end p-8 bg-gray-50 dark:bg-slate-800 border-none rounded-3xl">
                                        <FormField id="tier" label="Resource Tier" as="select" value={config.machineType} onChange={e => handleUpdate({ machineType: e.target.value as MachineType })}>
                                            <option value="Type I">Standard (Burstable vCPU)</option>
                                            <option value="Type II">Dedicated (Fixed Core Mapping)</option>
                                        </FormField>
                                        <FormField id="qty" label="Node Count" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </div>
                            )}

                            {config.type === 'vdc' && (
                                <Card className="space-y-12 !p-10 border-none bg-white dark:bg-slate-800 shadow-2xl">
                                    <SliderInput id="cpu" label="Reserved vCPU Cores" value={config.vdcCPU || 4} onChange={v => handleUpdate({ vdcCPU: v })} min={2} max={64} step={1} unit="Cores" pricePerUnit={PRICE_CPU_CORE_MONTHLY} />
                                    <SliderInput id="ram" label="Reserved RAM Allocation" value={config.vdcRAM || 8} onChange={v => handleUpdate({ vdcRAM: v })} min={4} max={256} step={4} unit="GB" pricePerUnit={PRICE_RAM_GB_MONTHLY} />
                                    <SliderInput id="storage" label="High-Performance Block Storage" value={config.vdcFlashStorage || 100} onChange={v => handleUpdate({ vdcFlashStorage: v })} min={50} max={5000} step={50} unit="GB" pricePerUnit={PRICE_FLASH_GB_MONTHLY} />
                                </Card>
                            )}

                            {config.type === 'ready-plan' && (
                                <div className="space-y-6">
                                     <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                        {mockReadyPlans.map(p => (
                                            <VisualCard 
                                                key={p.id}
                                                active={config.readyPlanId === p.id}
                                                onClick={() => handleUpdate({ readyPlanId: p.id })}
                                                icon="fas fa-rocket"
                                                title={p.name}
                                                price={p.priceMonthly}
                                                description={p.description}
                                            />
                                        ))}
                                    </div>
                                    <div className="max-w-xs p-4 bg-gray-50 dark:bg-slate-800 rounded-2xl">
                                        <FormField id="qty-rp" label="Nodes in Cluster" type="number" value={config.quantity || 1} onChange={e => handleUpdate({ quantity: Math.max(1, parseInt(e.target.value) || 1) })} disabled={isEditing} />
                                    </div>
                                </div>
                            )}
                        </section>

                        {/* Step 3: Performance & Base Options */}
                        <section className="space-y-10">
                            <SectionHeader step={3} title="Stack & Connectivity" subtitle="Accelerate your instance and configure the network layer." />

                            {config.type === 'instance' && (
                                <div className="bg-white dark:bg-slate-800 rounded-3xl overflow-hidden shadow-md border border-gray-100 dark:border-slate-700">
                                    <CollapsibleSection 
                                        title="GPU Acceleration (NVIDIA AI-Optimized)" 
                                        initialOpen={config.gpuEnabled}
                                        className="!py-0"
                                    >
                                        <div className="space-y-6 p-8">
                                            <div className={`flex justify-between items-center p-8 rounded-3xl border-2 transition-all ${config.gpuEnabled ? 'bg-emerald-500/5 border-[#679a41]/30 shadow-inner' : 'bg-gray-50/50 dark:bg-slate-800/40 border-gray-100 dark:border-slate-800'}`}>
                                                <div>
                                                    <p className="font-black text-lg text-[#293c51] dark:text-gray-100">Add Graphics Processing Power</p>
                                                    <p className="text-sm text-gray-500 font-medium mt-1">Requires Type II Infrastructure. Essential for Large Language Models and scientific computing.</p>
                                                </div>
                                                <ToggleSwitch id="gpu" checked={!!config.gpuEnabled} onChange={v => handleUpdate({ gpuEnabled: v })} disabled={config.machineType === 'Type I'} size="md" />
                                            </div>
                                            {config.gpuEnabled && (
                                                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 animate-fade-in p-8 bg-gray-50 dark:bg-slate-900 border rounded-3xl">
                                                    <FormField id="family" label="Silicon Architecture" as="select" value={config.gpuFamily} onChange={e => handleUpdate({ gpuFamily: e.target.value as any })}>
                                                        <option value="h100">NVIDIA H100 Hopper (Next-Gen)</option>
                                                        <option value="tesla">NVIDIA Tesla (Ampere/Pascal)</option>
                                                    </FormField>
                                                    {config.gpuFamily === 'h100' ? (
                                                        <FormField id="slices" label="MIG Slices" as="select" value={config.h100Slices} onChange={e => handleUpdate({ h100Slices: parseInt(e.target.value) })}>
                                                            {H100_SLICE_OPTIONS.map(opt => <option key={opt} value={opt}>{opt} Slice ({opt * 12}GB VRAM)</option>)}
                                                        </FormField>
                                                    ) : (
                                                        <FormField id="tesla" label="Workstation Bundle" as="select" value={config.teslaOptionId} onChange={e => handleUpdate({ teslaOptionId: e.target.value })}>
                                                            <option value="">Select Bundle...</option>
                                                            {mockTeslaGpuOptions.map(o => <option key={o.id} value={o.id}>{o.label} — ${o.priceMonthly}/mo</option>)}
                                                        </FormField>
                                                    )}
                                                </div>
                                            )}
                                        </div>
                                    </CollapsibleSection>
                                </div>
                            )}

                            <div className="bg-white dark:bg-slate-800 rounded-3xl overflow-hidden shadow-md border border-gray-100 dark:border-slate-700">
                                <CollapsibleSection title="Software Environment & Virtual NICs" initialOpen={true} className="!py-0">
                                    <div className="space-y-8 p-8">
                                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                                            {topOsChoices.map(os => (
                                                <button 
                                                    key={os.id} 
                                                    type="button"
                                                    onClick={() => handleUpdate({ osSoftware: os.id })}
                                                    className={`flex items-center gap-4 p-5 border-2 rounded-2xl transition-all ${config.osSoftware === os.id ? 'border-[#679a41] bg-white dark:bg-slate-800 shadow-lg ring-1 ring-[#679a41]/20 transform scale-105' : 'bg-gray-50/50 dark:bg-slate-800/30 hover:border-gray-300'}`}
                                                >
                                                    <Icon name={os.icon} className={`text-3xl ${config.osSoftware === os.id ? 'text-[#679a41]' : 'text-gray-400'}`} />
                                                    <span className={`text-sm font-black uppercase tracking-tight ${config.osSoftware === os.id ? 'text-[#293c51] dark:text-gray-100' : 'text-gray-500'}`}>{os.name}</span>
                                                </button>
                                            ))}
                                            <Link to="/app/billing/cloudedge-configurations/os-images" className="flex items-center justify-center p-5 border-2 border-dashed border-[#679a41]/30 rounded-2xl text-[11px] font-black text-[#679a41] dark:text-emerald-400 hover:bg-[#679a41]/5 transition-all uppercase tracking-[2px]">
                                                Open Image Gallery
                                            </Link>
                                        </div>

                                        <div className="bg-gray-50/70 dark:bg-slate-800/40 p-10 rounded-3xl border border-gray-100 dark:border-slate-800">
                                            <div className="flex items-center gap-4 mb-6">
                                                <div className="w-10 h-10 bg-white dark:bg-slate-700 rounded-xl flex items-center justify-center shadow-sm">
                                                    <Icon name="fas fa-network-wired" className="text-[#679a41]" />
                                                </div>
                                                <h4 className="font-extrabold text-base tracking-tight">Networking Interfaces</h4>
                                            </div>
                                            <div className="max-w-md">
                                                <FormField 
                                                    id="nic-select" 
                                                    label="Hardware NIC Count" 
                                                    as="select" 
                                                    value={config.nics} 
                                                    onChange={e => handleUpdate({ nics: e.target.value })}
                                                    hint="Multi-NIC configuration allows for complex VLAN separation and DMZ setups."
                                                />
                                            </div>
                                        </div>
                                    </div>
                                </CollapsibleSection>
                            </div>

                            <div className="bg-white dark:bg-slate-800 rounded-3xl overflow-hidden shadow-md border border-gray-100 dark:border-slate-700">
                                <CollapsibleSection title="Storage Expansion & Secondary Disks" className="!py-0">
                                    <div className="space-y-4 p-8">
                                        <div className={`flex justify-between items-center p-6 border rounded-2xl transition-all ${config.flashDiskEnabled ? 'bg-[#679a41]/5 dark:bg-emerald-900/10 border-[#679a41]/20' : 'bg-gray-50/50 dark:bg-slate-800/40 border-gray-100'}`}>
                                            <div className="flex items-center gap-4">
                                                <Icon name="fas fa-database" className={`text-xl ${config.flashDiskEnabled ? 'text-[#679a41]' : 'text-gray-400'}`} />
                                                <div>
                                                    <p className="text-sm font-bold text-[#293c51] dark:text-gray-100">Attach Volume</p>
                                                    <p className="text-xs text-gray-500">Mount a separate high-speed block storage volume.</p>
                                                </div>
                                            </div>
                                            <ToggleSwitch id="fdisk" checked={!!config.flashDiskEnabled} onChange={v => handleUpdate({ flashDiskEnabled: v })} />
                                        </div>
                                        {config.flashDiskEnabled && (
                                            <div className="animate-fade-in p-8 bg-gray-50 dark:bg-slate-900 border rounded-3xl shadow-sm space-y-8">
                                                <FormField id="dtype" label="Block Storage Protocol" as="select" value={config.flashDiskType} onChange={e => handleUpdate({ flashDiskType: e.target.value as any })}>
                                                    <option value="SSD">Standard Performance (SSD)</option>
                                                    <option value="NVMe">Ultra Performance (NVMe)</option>
                                                </FormField>
                                                <SliderInput id="fsize" label="Volume Capacity" value={config.flashDiskGB || 0} onChange={v => handleUpdate({ flashDiskGB: v })} min={0} max={2000} step={50} unit="GB" pricePerUnit={config.flashDiskType === 'NVMe' ? PRICE_FLASH_DISK_NVME_GB_MONTHLY : PRICE_FLASH_DISK_SSD_GB_MONTHLY} />
                                            </div>
                                        )}
                                    </div>
                                </CollapsibleSection>
                            </div>
                        </section>

                        {/* Step 4: Additional Resources */}
                        <section className="space-y-10">
                            <SectionHeader step={4} title="Cloud Managed Services" subtitle="Enterprise add-ons for security and business continuity." />
                            <Card className="space-y-12 !p-12 border-none bg-white dark:bg-slate-800 shadow-2xl rounded-[2.5rem]">
                                <SliderInput 
                                    id="ips-addon" 
                                    label="Static IPv4 Nodes" 
                                    value={config.staticPublicIPs || 0} 
                                    onChange={v => handleUpdate({ staticPublicIPs: v })} 
                                    min={0} max={64} step={1} unit="IPs" 
                                    pricePerUnit={PRICE_STATIC_IP_MONTHLY}
                                />
                                <SliderInput 
                                    id="obj-storage" 
                                    label="Managed Object Storage (S3)" 
                                    value={config.objectStorageGB || 0} 
                                    onChange={v => handleUpdate({ objectStorageGB: v })} 
                                    min={0} max={10000} step={100} unit="GB" 
                                    pricePerUnit={PRICE_OBJECT_STORAGE_GB_MONTHLY}
                                />
                                <SliderInput 
                                    id="adv-backup" 
                                    label="WorldPosta Data Protection (Veeam)" 
                                    value={config.advancedBackupGB || 0} 
                                    onChange={v => handleUpdate({ advancedBackupGB: v })} 
                                    min={0} max={5000} step={100} unit="GB" 
                                    pricePerUnit={PRICE_ADVANCED_BACKUP_GB_MONTHLY}
                                />
                            </Card>
                        </section>
                    </div>

                    {/* RIGHT PANEL: SUMMARY & EXECUTION */}
                    <div className="lg:col-span-4">
                        <Card className="sticky top-28 border-none dark:border-slate-700 shadow-[0_20px_50px_rgba(0,0,0,0.1)] overflow-hidden !p-0 rounded-[2rem] bg-white dark:bg-slate-800">
                            <div className="p-8 bg-[#293c51] text-white">
                                <div className="flex items-center justify-between mb-4">
                                    <h3 className="text-xl font-black uppercase tracking-widest flex items-center gap-2">
                                        <Icon name="fas fa-file-invoice-dollar" />
                                        Quote Summary
                                    </h3>
                                </div>
                                <div className="flex flex-col gap-1">
                                    <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">Environment Label</p>
                                    <p className="text-lg font-black truncate">{config.name || 'UNNAMED_STRATEGY'}</p>
                                </div>
                            </div>

                            <div className="p-8 space-y-6">
                                <div className="space-y-1">
                                    <PriceBreakdownRow label="Strategy" value={config.type === 'instance' ? 'Compute Nodes' : config.type === 'vdc' ? 'VDC Pool' : 'Blueprint'} />
                                    <PriceBreakdownRow label="Zone" value={mockRegions.find(r => r.id === config.deploymentRegion)?.name || '-'} />
                                    <PriceBreakdownRow 
                                        label="Provisioning" 
                                        value={config.billingMode === 'payg_wallet' ? 'PAYG (Hourly)' : 'Sub (Fixed)'} 
                                    />
                                    {config.billingMode === 'subscription' && (
                                        <PriceBreakdownRow label="Commitment" value={`${config.subscriptionTermValue} ${config.subscriptionTermUnit}${config.subscriptionTermValue! > 1 ? 's' : ''}`} />
                                    )}
                                </div>

                                <PriceBreakdownRow 
                                    label="Monthly Base Total" 
                                    value={`$${subtotal.toFixed(2)}`} 
                                    subValue={config.billingMode === 'payg_wallet' ? `~ $${(subtotal/730).toFixed(4)}/HR` : 'Standard Rate'}
                                    isTotal={true}
                                />

                                {config.quantity! > 1 && (
                                    <div className="flex justify-between items-center p-5 bg-gray-50 dark:bg-slate-900/50 rounded-2xl border-2 border-dashed border-gray-100 dark:border-slate-700">
                                        <div className="flex flex-col">
                                            <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Aggregate Cost</span>
                                            <span className="text-sm font-bold text-[#293c51] dark:text-gray-100">All Nodes (x{config.quantity})</span>
                                        </div>
                                        <span className="font-black text-xl text-[#679a41] dark:text-emerald-400">${grandTotal.toFixed(2)}</span>
                                    </div>
                                )}

                                <div className="pt-4">
                                    {config.billingMode === 'payg_wallet' && (
                                        <div className={`p-6 rounded-3xl mb-8 text-center transition-all border-2 ${grandTotal > walletBalance ? 'bg-red-500/5 border-red-500/20' : 'bg-emerald-500/5 border-[#679a41]/20'}`}>
                                            <p className="text-[10px] text-gray-400 uppercase font-black tracking-[3px] mb-2">Wallet Liquidity</p>
                                            <p className={`text-4xl font-black ${grandTotal > walletBalance ? 'text-red-600' : 'text-[#293c51] dark:text-white'}`}>
                                                ${walletBalance.toFixed(2)}
                                            </p>
                                            {grandTotal > walletBalance && (
                                                <button type="button" onClick={() => setIsTopUpModalOpen(true)} className="flex items-center justify-center gap-2 w-full text-xs text-red-600 dark:text-red-400 font-black uppercase tracking-widest mt-5 bg-white dark:bg-slate-900 h-12 rounded-2xl shadow-sm hover:shadow-md transition-all">
                                                    <Icon name="fas fa-plus-circle" /> Add Funds Now
                                                </button>
                                            )}
                                        </div>
                                    )}

                                    <Button 
                                        fullWidth 
                                        size="lg" 
                                        onClick={handleSave}
                                        disabled={!config.name || (config.billingMode === 'payg_wallet' && grandTotal > walletBalance)}
                                        className="h-16 text-sm shadow-2xl shadow-green-500/30 font-black uppercase tracking-[2px] rounded-3xl transform hover:scale-[1.02] transition-transform active:scale-95"
                                    >
                                        {isEditing ? 'Confirm Update' : (config.quantity! > 1 ? 'Configure Cluster' : 'Commit Strategy')}
                                    </Button>

                                    <p className="text-[9px] text-gray-400 text-center mt-6 px-6 font-bold uppercase tracking-widest opacity-60">
                                        Subject to WorldPosta Global SLA Terms
                                    </p>
                                </div>
                            </div>
                        </Card>
                    </div>
                </div>
            ) : (
                /* STEP 2: BULK NAMING */
                <div className="max-w-2xl mx-auto py-20">
                    <Card className="animate-fade-in shadow-[0_50px_100px_rgba(0,0,0,0.15)] overflow-hidden !p-0 rounded-[3rem] border-none bg-white dark:bg-slate-800">
                        <div className="p-12 bg-gradient-to-br from-[#679a41] to-[#588836] text-white">
                            <h3 className="text-3xl font-black mb-2 tracking-tight">Identity Assignment</h3>
                            <p className="text-white/80 font-medium">Assign unique FQDNs or hostnames to your {config.quantity} compute nodes.</p>
                        </div>
                        <div className="p-12 space-y-6 max-h-[55vh] overflow-y-auto custom-scrollbar">
                            {individualNames.map((name, idx) => (
                                <div key={idx} className="flex gap-4 items-end">
                                    <div className="w-12 h-12 rounded-2xl bg-gray-100 dark:bg-slate-700 flex items-center justify-center font-black text-gray-400 flex-shrink-0 mb-4">
                                        {idx + 1}
                                    </div>
                                    <FormField 
                                        id={`name-${idx}`}
                                        label={`Node Label`}
                                        value={name}
                                        onChange={e => {
                                            const newNames = [...individualNames];
                                            newNames[idx] = e.target.value;
                                            setIndividualNames(newNames);
                                        }}
                                        required
                                        placeholder={`vm-cluster-node-0${idx + 1}`}
                                        wrapperClassName="flex-grow"
                                    />
                                </div>
                            ))}
                        </div>
                        <div className="p-12 border-t bg-gray-50 dark:bg-slate-900/50 flex justify-between gap-6">
                            <Button variant="ghost" onClick={() => setPageStep(1)} className="font-bold">Return to Config</Button>
                            <Button onClick={handleFinalSubmit} className="shadow-2xl shadow-green-500/30 px-12 h-14 font-black uppercase tracking-widest rounded-2xl">Initialize Provisioning</Button>
                        </div>
                    </Card>
                </div>
            )}

            <Modal 
                isOpen={isTopUpModalOpen} 
                onClose={() => setIsTopUpModalOpen(false)} 
                title="Secure Wallet Recharge" 
                size="sm"
            >
                <div className="space-y-8 pt-4">
                    <div className="p-5 bg-sky-500/10 dark:bg-sky-500/5 text-sky-700 dark:text-sky-300 text-xs font-bold rounded-2xl flex gap-4 items-start border border-sky-500/20">
                        <Icon name="fas fa-lock" className="mt-1" />
                        <p className="leading-relaxed">All transactions are processed through Stripe Financial Services. Credits are instantly available for resource consumption.</p>
                    </div>
                    <FormField 
                        id="topup-amt" 
                        label="Recharge Value (USD)" 
                        type="number" 
                        placeholder="100.00" 
                        value={modalTopUpAmount}
                        onChange={(e) => setModalTopUpAmount(parseFloat(e.target.value) || '')}
                        inputClassName="text-xl font-black py-4 text-center"
                    />
                    <div className="flex flex-col gap-3">
                         <Button fullWidth onClick={() => { 
                            const amount = typeof modalTopUpAmount === 'number' ? modalTopUpAmount : 50;
                            handleTopUp(amount); 
                            setIsTopUpModalOpen(false); 
                        }} size="lg" className="h-14 font-black uppercase tracking-widest rounded-2xl">Confirm Payment</Button>
                        <Button variant="ghost" fullWidth onClick={() => setIsTopUpModalOpen(false)} className="font-bold text-gray-400">Dismiss</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
};
